1	package com.reclaim.portal.auth.service;
2	
3	import com.reclaim.portal.auth.entity.User;
4	import com.reclaim.portal.auth.repository.UserRepository;
5	import org.springframework.security.core.authority.SimpleGrantedAuthority;
6	import org.springframework.security.core.userdetails.UserDetails;
7	import org.springframework.security.core.userdetails.UserDetailsService;
8	import org.springframework.security.core.userdetails.UsernameNotFoundException;
9	import org.springframework.stereotype.Service;
10	
11	import java.util.stream.Collectors;
12	
13	@Service
14	public class CustomUserDetailsService implements UserDetailsService {
15	
16	    private final UserRepository userRepository;
17	
18	    public CustomUserDetailsService(UserRepository userRepository) {
19	        this.userRepository = userRepository;
20	    }
21	
22	    @Override
23	    public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
24	        User user = userRepository.findByUsername(username)
25	            .orElseThrow(() -> new UsernameNotFoundException("User not found: " + username));
26	
27	        return org.springframework.security.core.userdetails.User.builder()
28	            .username(user.getUsername())
29	            .password(user.getPasswordHash())
30	            .disabled(!user.isEnabled())
31	            .accountExpired(false)
32	            .credentialsExpired(false)
33	            .accountLocked(user.isLocked())
34	            .authorities(user.getRoles().stream()
35	                .map(role -> new SimpleGrantedAuthority(role.getName()))
36	                .collect(Collectors.toList()))
37	            .build();
38	    }
39	}
