38	/**
39	 * Serves stored files (signatures, evidence images) via a controlled endpoint.
40	 * Delegates all path validation and traversal protection to {@link StorageService}.
41	 * Requires authentication — inherits the global security filter chain rules.
42	 */
43	@RestController
44	@RequestMapping("/storage")
45	public class StorageFileController {
46	
47	    private static final Logger log = LoggerFactory.getLogger(StorageFileController.class);
48	
49	    private static final Map<String, MediaType> EXTENSION_MEDIA_TYPE = Map.of(
50	            "png", MediaType.IMAGE_PNG,
51	            "jpg", MediaType.IMAGE_JPEG,
52	            "jpeg", MediaType.IMAGE_JPEG
53	    );
54	
55	    private final StorageService storageService;
56	    private final EvidenceFileRepository evidenceFileRepository;
57	    private final SignatureArtifactRepository signatureArtifactRepository;
58	    private final ContractInstanceRepository contractInstanceRepository;
59	    private final AppealRepository appealRepository;
60	    private final ReviewImageRepository reviewImageRepository;
61	    private final ReviewRepository reviewRepository;
62	    private final OrderRepository orderRepository;
63	    private final UserRepository userRepository;
64	
65	    public StorageFileController(StorageService storageService,
66	                                 EvidenceFileRepository evidenceFileRepository,
67	                                 SignatureArtifactRepository signatureArtifactRepository,
68	                                 ContractInstanceRepository contractInstanceRepository,
69	                                 AppealRepository appealRepository,
70	                                 ReviewImageRepository reviewImageRepository,
71	                                 ReviewRepository reviewRepository,
72	                                 OrderRepository orderRepository,
73	                                 UserRepository userRepository) {
74	        this.storageService = storageService;
75	        this.evidenceFileRepository = evidenceFileRepository;
76	        this.signatureArtifactRepository = signatureArtifactRepository;
77	        this.contractInstanceRepository = contractInstanceRepository;
78	        this.reviewImageRepository = reviewImageRepository;
79	        this.reviewRepository = reviewRepository;
80	        this.orderRepository = orderRepository;
81	        this.appealRepository = appealRepository;
82	        this.userRepository = userRepository;
83	    }
84	
85	    /**
86	     * Serves a stored file by its relative path. The path is extracted from
87	     * everything after {@code /storage/}, e.g. {@code /storage/signatures/abc.png}
88	     * resolves to relative path {@code signatures/abc.png}.
89	     *
90	     * <p>Access control: authentication is required (enforced by the global security
91	     * filter chain). File names are UUID-based, providing enumeration protection.
92	     * Ownership is verified by looking up the path in the database and checking
93	     * that the authenticated user is the file's owner, is the assigned reviewer,
94	     * or is an admin.
95	     */
96	    @GetMapping("/**")
97	    public ResponseEntity<byte[]> serveFile(HttpServletRequest request, Authentication auth) {
98	        // Require authentication — the filter chain enforces this, but we verify
99	        // explicitly here as an additional defence-in-depth check.
100	        if (auth == null || !auth.isAuthenticated()) {
101	            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
102	        }
103	
104	        // Extract the relative path after "/storage/"
105	        String fullPath = request.getRequestURI();
106	        String contextPath = request.getContextPath();
107	        String relativePath = fullPath.substring(contextPath.length() + "/storage/".length());
108	
109	        if (relativePath.isBlank()) {
110	            return ResponseEntity.badRequest().build();
111	        }
112	
113	        // Ownership check — admins can access all files; reviewers and users only their own
114	        // or assigned entities.
115	        if (!hasFileAccess(relativePath, auth)) {
116	            log.warn("Storage access denied: path='{}' user='{}'", relativePath, auth.getName());
117	            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
118	        }
119	
120	        log.debug("Storage file access: path='{}' by user='{}'", relativePath, auth.getName());
121	
122	        try {
123	            byte[] data = storageService.retrieve(relativePath);
124	
125	            // Verify file integrity against stored checksum
126	            String storedChecksum = resolveStoredChecksum(relativePath);
127	            if (!verifyIntegrity(data, storedChecksum)) {
128	                log.warn("File integrity check failed: path='{}' user='{}'", relativePath, auth.getName());
129	                throw new com.reclaim.portal.common.exception.BusinessRuleException(
130	                        "File integrity check failed for: " + relativePath);
131	            }
132	
133	            MediaType contentType = resolveContentType(relativePath);
134	
135	            return ResponseEntity.ok()
136	                    .contentType(contentType)
137	                    .contentLength(data.length)
138	                    .cacheControl(CacheControl.maxAge(1, TimeUnit.HOURS).cachePrivate())
139	                    .body(data);
140	        } catch (com.reclaim.portal.common.exception.EntityNotFoundException e) {
141	            return ResponseEntity.notFound().build();
142	        } catch (com.reclaim.portal.common.exception.BusinessRuleException e) {
143	            log.warn("Blocked storage file request: path='{}' user='{}' reason='{}'",
144	                    relativePath, auth.getName(), e.getMessage());
145	            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
146	        }
147	    }
148	
149	    /**
150	     * Checks whether the authenticated principal may access the given relative storage path.
151	     * Admins are allowed unrestricted access (for dispute resolution and audit).
152	     * Reviewers may access files on orders/contracts/appeals they are assigned to.
153	     * Regular users are allowed only files that belong to them according to the database records.
154	     */
155	    private boolean hasFileAccess(String relativePath, Authentication auth) {
156	        // Admins can access all stored files (for dispute resolution and audit)
157	        if (isAdmin(auth)) return true;
158	
159	        Long actorId = resolveUserId(auth);
160	        if (actorId == null) return false;
161	
162	        boolean staff = isStaff(auth);
163	
164	        if (relativePath.startsWith("signatures/")) {
165	            // Signatures contain PII (handwriting). Only the contract owner may view.
166	            // Reviewers see masked PII by default — admin reveal (via admin panel) is required.
167	            List<SignatureArtifact> artifacts = signatureArtifactRepository.findByFilePath(relativePath);
168	            for (SignatureArtifact artifact : artifacts) {
169	                ContractInstance contract = contractInstanceRepository
170	                        .findById(artifact.getContractId()).orElse(null);
171	                if (contract != null && actorId.equals(contract.getUserId())) return true;
172	            }
173	            return false;
174	        }
175	
176	        if (relativePath.startsWith("evidence/")) {
177	            // Evidence: accessible to the uploader, the contract/appeal owner.
178	            // Reviewers do NOT get automatic access — consistent with PII masking model.
179	            List<EvidenceFile> files = evidenceFileRepository.findByFilePath(relativePath);
180	            for (EvidenceFile f : files) {
181	                if (actorId.equals(f.getUploadedBy())) return true;
182	                if ("CONTRACT".equals(f.getEntityType())) {
183	                    ContractInstance contract = contractInstanceRepository.findById(f.getEntityId()).orElse(null);
184	                    if (contract != null && actorId.equals(contract.getUserId())) return true;
185	                }
186	                if ("APPEAL".equals(f.getEntityType())) {
187	                    Appeal appeal = appealRepository.findById(f.getEntityId()).orElse(null);
188	                    if (appeal != null && actorId.equals(appeal.getAppellantId())) return true;
189	                }
190	            }
191	            return false;
192	        }
193	
194	        if (relativePath.startsWith("reviews/")) {
195	            // Review images: accessible to the review author or the order owner.
196	            // Reviewers assigned to the order may also access.
197	            List<ReviewImage> images = reviewImageRepository.findByFilePath(relativePath);
198	            for (ReviewImage img : images) {
199	                Review review = reviewRepository.findById(img.getReviewId()).orElse(null);
200	                if (review != null) {
201	                    // Review author can see their own images
202	                    if (actorId.equals(review.getReviewerUserId())) return true;
203	                    // Order owner can see reviews for their orders
204	                    Order order = orderRepository.findById(review.getOrderId()).orElse(null);
205	                    if (order != null && actorId.equals(order.getUserId())) return true;
206	                    if (staff && order != null && actorId.equals(order.getReviewerId())) return true;
207	                }
208	            }
209	            return false;
210	        }
211	
212	        // Unknown subdirectory: deny by default
213	        return false;
214	    }
215	
216	    /**
217	     * Looks up the stored SHA-256 checksum for a file by its relative path.
218	     * Checks evidence files and signature artifacts. Returns null if no record is found
219	     * (e.g. review images which have no checksum tracked in those tables).
220	     */
221	    private String resolveStoredChecksum(String relativePath) {
222	        List<EvidenceFile> evidenceFiles = evidenceFileRepository.findByFilePath(relativePath);
223	        if (!evidenceFiles.isEmpty()) {
224	            return evidenceFiles.get(0).getChecksum();
225	        }
226	        List<SignatureArtifact> sigArtifacts = signatureArtifactRepository.findByFilePath(relativePath);
227	        if (!sigArtifacts.isEmpty()) {
228	            return sigArtifacts.get(0).getChecksum();
229	        }
230	        return null;
231	    }
232	
233	    /**
234	     * Computes a SHA-256 checksum from the given bytes and compares against the stored value.
235	     * Returns true when storedChecksum is null (no checksum to verify against) or when checksums match.
236	     */
237	    private boolean verifyIntegrity(byte[] data, String storedChecksum) {
238	        if (storedChecksum == null) return true;
239	        try {
240	            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
241	            String computed = java.util.HexFormat.of().formatHex(digest.digest(data));
242	            return storedChecksum.equals(computed);
243	        } catch (java.security.NoSuchAlgorithmException e) {
244	            return true; // SHA-256 is always available on any compliant JVM
245	        }
246	    }
247	
248	    private Long resolveUserId(Authentication auth) {
249	        if (auth == null) return null;
250	        String username = ((UserDetails) auth.getPrincipal()).getUsername();
251	        return userRepository.findByUsername(username)
252	                .map(User::getId)
253	                .orElse(null);
254	    }
255	
256	    private boolean isAdmin(Authentication auth) {
257	        if (auth == null) return false;
258	        return auth.getAuthorities().stream()
259	                .map(GrantedAuthority::getAuthority)
260	                .anyMatch(a -> a.equals("ROLE_ADMIN"));
261	    }
262	
263	    private boolean isStaff(Authentication auth) {
264	        if (auth == null) return false;
265	        return auth.getAuthorities().stream()
266	                .map(GrantedAuthority::getAuthority)
267	                .anyMatch(a -> a.equals("ROLE_REVIEWER") || a.equals("ROLE_ADMIN"));
268	    }
269	
270	    private MediaType resolveContentType(String filePath) {
271	        int dotIndex = filePath.lastIndexOf('.');
272	        if (dotIndex >= 0 && dotIndex < filePath.length() - 1) {
273	            String ext = filePath.substring(dotIndex + 1).toLowerCase();
274	            MediaType mediaType = EXTENSION_MEDIA_TYPE.get(ext);
275	            if (mediaType != null) {
276	                return mediaType;
277	            }
278	        }
279	        return MediaType.APPLICATION_OCTET_STREAM;
280	    }
281	}
