222	    public ContractInstance signContract(Long instanceId, Long signerId,
223	                                         String signatureType, byte[] sigData) {
224	        ContractInstance instance = loadInstance(instanceId);
225	        // Only the contract's user may sign
226	        if (signerId == null || !signerId.equals(instance.getUserId())) {
227	            throw new BusinessRuleException("Access denied to contract");
228	        }
229	        requireStatus(instance, STATUS_CONFIRMED);
230	
231	        // Salt the signature hash for storage security
232	        String salt = java.util.UUID.randomUUID().toString();
233	        String encodedSig = java.util.Base64.getEncoder().encodeToString(sigData);
234	        String signatureHash = sha256Hex((salt + ":" + encodedSig).getBytes(java.nio.charset.StandardCharsets.UTF_8));
235	
236	        // Wrap bytes as a MultipartFile for StorageService
237	        MultipartFile sigFile = new ByteArrayMultipartFile(
238	                "signature",
239	                "signature_" + signerId + ".png",
240	                "image/png",
241	                sigData
242	        );
243	
244	        StorageResult result = storageService.store(sigFile, "signatures");
245	
246	        SignatureArtifact artifact = new SignatureArtifact();
247	        artifact.setContractId(instanceId);
248	        artifact.setSignerId(signerId);
249	        artifact.setSignatureType(signatureType);
250	        artifact.setFilePath(result.filePath());
251	        artifact.setSignatureHash(salt + ":" + signatureHash);
252	        artifact.setChecksum(result.checksum());
253	        artifact.setSignedAt(LocalDateTime.now());
254	        signatureRepository.save(artifact);
255	
256	        instance.setContractStatus(STATUS_SIGNED);
257	        instance.setSignedAt(LocalDateTime.now());
258	        instance.setUpdatedAt(LocalDateTime.now());
259	        log.info("Contract signed: id={}, signerId={}", instanceId, signerId);
