319	    /**
320	     * Computes the effective display status of a contract instance.
321	     * Terminal/explicit states are returned as-is; date-based transitions are applied
322	     * to SIGNED/ACTIVE/RENEWED contracts.
323	     */
324	    public String getContractStatus(ContractInstance instance) {
325	        String stored = instance.getContractStatus();
326	
327	        if (STATUS_TERMINATED.equals(stored) || STATUS_VOIDED.equals(stored)
328	                || STATUS_ARCHIVED.equals(stored)) {
329	            return stored;
330	        }
331	        if (STATUS_RENEWED.equals(stored)) {
332	            return STATUS_RENEWED;
333	        }
334	        // Pre-signing statuses are returned as-is (INITIATED, CONFIRMED)
335	        if (STATUS_INITIATED.equals(stored) || STATUS_CONFIRMED.equals(stored)) {
336	            return stored;
337	        }
338	
339	        // Date-based transitions apply only to SIGNED (post-signing) contracts
340	        LocalDate today = LocalDate.now();
341	        LocalDate endDate = instance.getEndDate();
342	
343	        if (endDate != null) {
344	            if (endDate.isBefore(today)) {
345	                return STATUS_TERMINATED;
346	            }
347	            int expiringSoonDays = reclaimProperties.getContracts().getExpiringSoonDays();
348	            if (endDate.isBefore(today.plusDays(expiringSoonDays))) {
349	                return STATUS_EXPIRING_SOON;
350	            }
351	        }
352	
353	        return STATUS_ACTIVE;
354	    }
