459	    /**
460	     * Replaces {{fieldName}} placeholders in the template content with values from
461	     * the provided fieldValues string. Accepts JSON object format or legacy key=value pairs.
462	     * Validates that all required clause fields have non-blank values.
463	     */
464	    public String renderContent(String templateContent, String fieldValuesRaw,
465	                                 List<ContractClauseField> fields) {
466	        if (templateContent == null) return "";
467	
468	        Map<String, String> values = parseFieldValues(fieldValuesRaw);
469	
470	        // Always validate required fields — a missing required field is invalid regardless
471	        // of whether the caller passed an explicit fieldValues string.
472	        for (ContractClauseField field : fields) {
473	            if (field.isRequired()) {
474	                String value = values.get(field.getFieldName());
475	                if ((value == null || value.isBlank())
476	                        && (field.getDefaultValue() == null || field.getDefaultValue().isBlank())) {
477	                    throw new BusinessRuleException(
478	                            "Required clause field '" + field.getFieldName() + "' is missing");
479	                }
480	            }
481	        }
482	
483	        String rendered = templateContent;
484	        for (ContractClauseField field : fields) {
485	            String placeholder = "{{" + field.getFieldName() + "}}";
486	            String value = values.getOrDefault(field.getFieldName(),
487	                    field.getDefaultValue() != null ? field.getDefaultValue() : "");
488	            // HTML-escape user-supplied values to prevent stored XSS
489	            value = value.replace("&", "&amp;")
490	                         .replace("<", "&lt;")
491	                         .replace(">", "&gt;")
492	                         .replace("\"", "&quot;")
493	                         .replace("'", "&#39;");
494	            rendered = rendered.replace(placeholder, value);
495	        }
496	        return rendered;
497	    }
498	
499	    /**
500	     * Parses field values from either JSON object format (preferred) or legacy key=value format.
501	     * JSON format handles values containing commas, colons, quotes, etc. safely.
502	     */
503	    public Map<String, String> parseFieldValues(String fieldValuesRaw) {
504	        if (fieldValuesRaw == null || fieldValuesRaw.isBlank()) {
505	            return new LinkedHashMap<>();
506	        }
507	
508	        String trimmed = fieldValuesRaw.trim();
509	
510	        // Try JSON parsing first (preferred format)
511	        if (trimmed.startsWith("{")) {
512	            try {
513	                Map<String, String> result = objectMapper.readValue(trimmed,
514	                        new TypeReference<LinkedHashMap<String, String>>() {});
515	                return result;
516	            } catch (JsonProcessingException e) {
517	                log.warn("Failed to parse field values as JSON, falling back to legacy format: {}",
518	                        e.getMessage());
519	            }
520	        }
521	
522	        // Legacy key=value format (only for simple values without commas/colons)
523	        Map<String, String> map = new LinkedHashMap<>();
524	        for (String pair : trimmed.split(",")) {
525	            String[] kv = pair.split("=", 2);
526	            if (kv.length == 2) {
527	                map.put(kv[0].trim(), kv[1].trim());
528	            }
529	        }
530	        return map;
531	    }
532	
533	    private String sha256Hex(byte[] data) {
534	        try {
535	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
536	            byte[] hash = digest.digest(data);
537	            return HexFormat.of().formatHex(hash);
538	        } catch (NoSuchAlgorithmException e) {
539	            throw new RuntimeException("SHA-256 not available", e);
540	        }
541	    }
542	
543	    // =========================================================================
544	    // Inner utility: lightweight MultipartFile backed by a byte array
545	    // =========================================================================
546	
547	    /**
548	     * A minimal {@link MultipartFile} implementation backed by an in-memory byte array.
549	     * Used internally to wrap raw signature bytes before passing to StorageService.
550	     */
551	    private static final class ByteArrayMultipartFile implements MultipartFile {
552	
553	        private final String name;
554	        private final String originalFilename;
555	        private final String contentType;
556	        private final byte[] content;
557	
558	        ByteArrayMultipartFile(String name, String originalFilename,
559	                               String contentType, byte[] content) {
560	            this.name = name;
561	            this.originalFilename = originalFilename;
562	            this.contentType = contentType;
563	            this.content = content != null ? content : new byte[0];
564	        }
565	
566	        @Override public String getName()             { return name; }
567	        @Override public String getOriginalFilename() { return originalFilename; }
568	        @Override public String getContentType()      { return contentType; }
569	        @Override public boolean isEmpty()            { return content.length == 0; }
570	        @Override public long getSize()               { return content.length; }
571	        @Override public byte[] getBytes()            { return content; }
572	
573	        @Override
574	        public java.io.InputStream getInputStream() {
575	            return new java.io.ByteArrayInputStream(content);
576	        }
577	
578	        @Override
579	        public void transferTo(java.io.File dest) throws java.io.IOException {
580	            java.nio.file.Files.write(dest.toPath(), content);
581	        }
582	    }
583	}
