3	import com.reclaim.portal.catalog.entity.ItemFingerprint;
4	import com.reclaim.portal.catalog.entity.RecyclingItem;
5	import com.reclaim.portal.catalog.repository.ItemFingerprintRepository;
6	import com.reclaim.portal.catalog.repository.RecyclingItemRepository;
7	import com.reclaim.portal.common.exception.EntityNotFoundException;
8	import com.reclaim.portal.search.entity.SearchClickLog;
9	import com.reclaim.portal.search.entity.SearchLog;
10	import com.reclaim.portal.search.repository.SearchClickLogRepository;
11	import com.reclaim.portal.search.repository.SearchLogRepository;
12	import com.reclaim.portal.search.service.RankingService;
13	import com.reclaim.portal.search.service.SearchService;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.math.BigDecimal;
18	import java.nio.charset.StandardCharsets;
19	import java.security.MessageDigest;
20	import java.security.NoSuchAlgorithmException;
21	import java.time.LocalDateTime;
22	import java.util.HexFormat;
23	import java.util.List;
24	
25	@Service
26	@Transactional
27	public class CatalogService {
28	
29	    private static final org.slf4j.Logger log = org.slf4j.LoggerFactory.getLogger(CatalogService.class);
30	
31	    /** Immutable result of a search operation, bundling ranked items with the search session ID. */
32	    public record SearchResult(List<RecyclingItem> items, Long searchLogId) {}
33	
34	    private final RecyclingItemRepository recyclingItemRepository;
35	    private final ItemFingerprintRepository itemFingerprintRepository;
36	    private final SearchLogRepository searchLogRepository;
37	    private final SearchClickLogRepository searchClickLogRepository;
38	    private final SearchService searchService;
39	    private final RankingService rankingService;
40	
41	    public CatalogService(RecyclingItemRepository recyclingItemRepository,
42	                          ItemFingerprintRepository itemFingerprintRepository,
43	                          SearchLogRepository searchLogRepository,
44	                          SearchClickLogRepository searchClickLogRepository,
45	                          SearchService searchService,
46	                          RankingService rankingService) {
47	        this.recyclingItemRepository = recyclingItemRepository;
48	        this.itemFingerprintRepository = itemFingerprintRepository;
49	        this.searchLogRepository = searchLogRepository;
50	        this.searchClickLogRepository = searchClickLogRepository;
51	        this.searchService = searchService;
52	        this.rankingService = rankingService;
53	    }
54	
55	    public SearchResult searchItems(String keyword, String category, String condition,
56	                                     BigDecimal minPrice, BigDecimal maxPrice, Long userId) {
57	        List<RecyclingItem> results;
58	        try {
59	            results = recyclingItemRepository.searchItemsFullText(keyword, category, condition, minPrice, maxPrice);
60	        } catch (Exception e) {
61	            // Fallback to LIKE search (H2 or when full-text index not available)
62	            results = recyclingItemRepository.searchItems(keyword, category, condition, minPrice, maxPrice);
63	        }
64	
65	        if (keyword != null && !keyword.isBlank()) {
66	            searchService.updateTrends(keyword);
67	        }
68	
69	        // Deduplicate using persisted fingerprint hashes where available,
70	        // falling back to normalized title + attribute composite key.
71	        java.util.LinkedHashSet<String> seenKeys = new java.util.LinkedHashSet<>();
72	        List<RecyclingItem> deduped = new java.util.ArrayList<>();
73	        for (RecyclingItem item : results) {
74	            // Prefer the stored fingerprint hash (persisted by checkDuplicate flow)
75	            String key = itemFingerprintRepository.findByItemId(item.getId())
76	                    .map(fp -> fp.getFingerprintHash())
77	                    .orElseGet(() -> {
78	                        // Fallback: compute composite key from normalized title + attributes
79	                        String title = item.getNormalizedTitle() != null
80	                                ? item.getNormalizedTitle()
81	                                : (item.getTitle() != null ? item.getTitle().toLowerCase().trim() : "");
82	                        return title + "|" + (item.getCategory() != null ? item.getCategory() : "")
83	                                     + "|" + (item.getItemCondition() != null ? item.getItemCondition() : "");
84	                    });
85	            if (seenKeys.add(key)) {
86	                deduped.add(item);
87	            }
88	        }
89	
90	        List<RecyclingItem> rankedResults = rankingService.rankItems(deduped, userId);
91	
92	        SearchLog searchLog = new SearchLog();
93	        searchLog.setUserId(userId);
94	        searchLog.setSearchTerm(keyword);
95	        searchLog.setCategoryFilter(category);
96	        searchLog.setConditionFilter(condition);
97	        searchLog.setMinPrice(minPrice);
98	        searchLog.setMaxPrice(maxPrice);
99	        searchLog.setResultCount(rankedResults.size());
100	        searchLog.setSearchedAt(LocalDateTime.now());
101	        searchLog = searchLogRepository.save(searchLog);
102	
103	        return new SearchResult(rankedResults, searchLog.getId());
104	    }
105	
106	    @Transactional(readOnly = true)
107	    public RecyclingItem getItemById(Long id) {
108	        return recyclingItemRepository.findById(id)
109	                .orElseThrow(() -> new EntityNotFoundException("RecyclingItem", id));
110	    }
111	
112	    public void logClick(Long userId, Long searchLogId, Long itemId) {
113	        SearchClickLog clickLog = new SearchClickLog();
114	        clickLog.setUserId(userId);
115	        clickLog.setSearchLogId(searchLogId);
116	        clickLog.setItemId(itemId);
117	        clickLog.setClickedAt(LocalDateTime.now());
118	        searchClickLogRepository.save(clickLog);
119	    }
120	
121	    public String checkDuplicate(String title, String attributes) {
122	        String normalizedTitle = title == null ? "" : title.toLowerCase().trim().replaceAll("\\s+", " ");
123	        String combined = normalizedTitle + (attributes == null ? "" : attributes);
124	        String hash = sha256(combined);
125	
126	        if (itemFingerprintRepository.findByFingerprintHash(hash).isPresent()) {
127	            return "EXACT_DUPLICATE";
128	        }
129	
130	        List<RecyclingItem> sameTitle = recyclingItemRepository.findByNormalizedTitle(normalizedTitle);
131	        if (!sameTitle.isEmpty()) {
132	            return "NEAR_DUPLICATE";
133	        }
134	
135	        return "UNIQUE";
136	    }
137	
138	    private String sha256(String input) {
139	        try {
140	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
141	            byte[] hash = digest.digest(input.getBytes(StandardCharsets.UTF_8));
142	            return HexFormat.of().formatHex(hash);
143	        } catch (NoSuchAlgorithmException e) {
144	            throw new IllegalStateException("SHA-256 not available", e);
145	        }
146	    }
147	}
