1	package com.reclaim.portal.auth.service;
2	
3	import com.reclaim.portal.auth.dto.AuthResponse;
4	import com.reclaim.portal.auth.entity.LoginAttempt;
5	import com.reclaim.portal.auth.entity.RefreshToken;
6	import com.reclaim.portal.auth.entity.User;
7	import com.reclaim.portal.auth.repository.LoginAttemptRepository;
8	import com.reclaim.portal.auth.repository.RefreshTokenRepository;
9	import com.reclaim.portal.auth.repository.UserRepository;
10	import com.reclaim.portal.common.config.ReclaimProperties;
11	import com.reclaim.portal.common.exception.BusinessRuleException;
12	import com.reclaim.portal.common.exception.EntityNotFoundException;
13	import org.slf4j.Logger;
14	import org.slf4j.LoggerFactory;
15	import org.springframework.security.crypto.password.PasswordEncoder;
16	import org.springframework.stereotype.Service;
17	import org.springframework.transaction.annotation.Transactional;
18	
19	import java.nio.charset.StandardCharsets;
20	import java.security.MessageDigest;
21	import java.security.NoSuchAlgorithmException;
22	import java.time.LocalDateTime;
23	import java.util.HexFormat;
24	
25	@Service
26	@Transactional
27	public class AuthService {
28	
29	    private static final Logger log = LoggerFactory.getLogger(AuthService.class);
30	
31	    private final UserRepository userRepository;
32	    private final RefreshTokenRepository refreshTokenRepository;
33	    private final LoginAttemptRepository loginAttemptRepository;
34	    private final PasswordEncoder passwordEncoder;
35	    private final JwtService jwtService;
36	    private final ReclaimProperties reclaimProperties;
37	
38	    public AuthService(UserRepository userRepository,
39	                       RefreshTokenRepository refreshTokenRepository,
40	                       LoginAttemptRepository loginAttemptRepository,
41	                       PasswordEncoder passwordEncoder,
42	                       JwtService jwtService,
43	                       ReclaimProperties reclaimProperties) {
44	        this.userRepository = userRepository;
45	        this.refreshTokenRepository = refreshTokenRepository;
46	        this.loginAttemptRepository = loginAttemptRepository;
47	        this.passwordEncoder = passwordEncoder;
48	        this.jwtService = jwtService;
49	        this.reclaimProperties = reclaimProperties;
50	    }
51	
52	    public AuthResponse login(String username, String password, String ipAddress) {
53	        ReclaimProperties.Security security = reclaimProperties.getSecurity();
54	        LocalDateTime now = LocalDateTime.now();
55	
56	        User user = userRepository.findByUsername(username)
57	            .orElse(null);
58	
59	        // Check lock state before verifying credentials
60	        if (user != null && user.isLocked() && user.getLockedUntil() != null
61	                && user.getLockedUntil().isAfter(now)) {
62	            log.warn("Login rejected: account locked for user={} from ip={}", username, ipAddress);
63	            recordFailedAttempt(username, ipAddress, "Account is locked");
64	            throw new BusinessRuleException("Account is locked");
65	        }
66	
67	        if (user == null || !passwordEncoder.matches(password, user.getPasswordHash())) {
68	            if (user != null) {
69	                int attempts = user.getFailedAttempts() + 1;
70	                user.setFailedAttempts(attempts);
71	                if (attempts >= security.getMaxFailedAttempts()) {
72	                    user.setLocked(true);
73	                    user.setLockedUntil(now.plusMinutes(security.getLockoutMinutes()));
74	                    log.warn("Account locked after {} failed attempts: user={}", attempts, username);
75	                }
76	                user.setUpdatedAt(now);
77	                userRepository.save(user);
78	            }
79	            log.info("Login failed for user={} from ip={}", username, ipAddress);
80	            recordFailedAttempt(username, ipAddress, "Invalid credentials");
81	            throw new BusinessRuleException("Invalid username or password");
82	        }
83	
84	        // Successful authentication
85	        log.info("Login successful for user={}", username);
86	        user.setFailedAttempts(0);
87	        user.setLocked(false);
88	        user.setLockedUntil(null);
89	        user.setUpdatedAt(now);
90	        userRepository.save(user);
91	
92	        LoginAttempt successAttempt = new LoginAttempt();
93	        successAttempt.setUsername(username);
94	        successAttempt.setIpAddress(ipAddress);
95	        successAttempt.setSuccess(true);
96	        successAttempt.setAttemptedAt(now);
97	        loginAttemptRepository.save(successAttempt);
98	
99	        String accessToken = jwtService.generateAccessToken(user);
100	        String refreshTokenStr = jwtService.generateRefreshToken(user);
101	        String tokenHash = hashToken(refreshTokenStr);
102	
103	        RefreshToken refreshToken = new RefreshToken();
104	        refreshToken.setUserId(user.getId());
105	        refreshToken.setTokenHash(tokenHash);
106	        refreshToken.setExpiresAt(now.plusDays(security.getRefreshTokenDays()));
107	        refreshToken.setRevoked(false);
108	        refreshToken.setCreatedAt(now);
109	        refreshTokenRepository.save(refreshToken);
110	
111	        return new AuthResponse(accessToken, refreshTokenStr, user.isForcePasswordReset());
112	    }
113	
114	    public AuthResponse refresh(String refreshTokenStr) {
115	        if (!jwtService.isRefreshTokenValid(refreshTokenStr)) {
116	            log.warn("Refresh token validation failed");
117	            throw new BusinessRuleException("Invalid refresh token");
118	        }
119	
120	        String tokenHash = hashToken(refreshTokenStr);
121	        RefreshToken storedToken = refreshTokenRepository.findByTokenHash(tokenHash)
122	            .orElseThrow(() -> new BusinessRuleException("Refresh token not found"));
123	
124	        if (storedToken.isRevoked()) {
125	            throw new BusinessRuleException("Refresh token has been revoked");
126	        }
127	
128	        if (storedToken.getExpiresAt().isBefore(LocalDateTime.now())) {
129	            throw new BusinessRuleException("Refresh token has expired");
130	        }
131	
132	        storedToken.setRevoked(true);
133	        refreshTokenRepository.save(storedToken);
134	
135	        String username = jwtService.extractUsernameFromRefreshToken(refreshTokenStr);
136	        User user = userRepository.findByUsername(username)
137	            .orElseThrow(() -> new EntityNotFoundException("User not found: " + username));
138	
139	        ReclaimProperties.Security security = reclaimProperties.getSecurity();
140	        LocalDateTime now = LocalDateTime.now();
141	
142	        String newAccessToken = jwtService.generateAccessToken(user);
143	        String newRefreshTokenStr = jwtService.generateRefreshToken(user);
144	        String newTokenHash = hashToken(newRefreshTokenStr);
145	
146	        RefreshToken newRefreshToken = new RefreshToken();
147	        newRefreshToken.setUserId(user.getId());
148	        newRefreshToken.setTokenHash(newTokenHash);
149	        newRefreshToken.setExpiresAt(now.plusDays(security.getRefreshTokenDays()));
150	        newRefreshToken.setRevoked(false);
151	        newRefreshToken.setCreatedAt(now);
152	        refreshTokenRepository.save(newRefreshToken);
153	
154	        return new AuthResponse(newAccessToken, newRefreshTokenStr, user.isForcePasswordReset());
155	    }
156	
157	    public void logout(String refreshTokenStr) {
158	        String tokenHash = hashToken(refreshTokenStr);
159	        refreshTokenRepository.findByTokenHash(tokenHash).ifPresent(token -> {
160	            token.setRevoked(true);
161	            refreshTokenRepository.save(token);
162	        });
163	    }
164	
165	    public void changePassword(Long userId, String oldPass, String newPass) {
166	        User user = userRepository.findById(userId)
167	            .orElseThrow(() -> new EntityNotFoundException("User", userId));
168	
169	        if (!passwordEncoder.matches(oldPass, user.getPasswordHash())) {
170	            log.warn("Password change failed: incorrect current password for userId={}", userId);
171	            throw new BusinessRuleException("Current password is incorrect");
172	        }
173	
174	        validatePasswordStrength(newPass);
175	
176	        user.setPasswordHash(passwordEncoder.encode(newPass));
177	        user.setForcePasswordReset(false);
178	        user.setUpdatedAt(LocalDateTime.now());
179	        userRepository.save(user);
180	
181	        refreshTokenRepository.revokeAllByUserId(userId);
182	        log.info("Password changed successfully for userId={}", userId);
183	    }
184	
185	    private void validatePasswordStrength(String password) {
186	        if (password == null || password.length() < 12) {
187	            throw new BusinessRuleException(
188	                "Password must be at least 12 characters long");
189	        }
190	        if (!password.chars().anyMatch(Character::isUpperCase)) {
191	            throw new BusinessRuleException(
192	                "Password must contain at least one uppercase letter");
193	        }
194	        if (!password.chars().anyMatch(Character::isLowerCase)) {
195	            throw new BusinessRuleException(
196	                "Password must contain at least one lowercase letter");
197	        }
198	        if (!password.chars().anyMatch(Character::isDigit)) {
199	            throw new BusinessRuleException(
200	                "Password must contain at least one digit");
201	        }
202	        if (!password.chars().anyMatch(c -> !Character.isLetterOrDigit(c))) {
203	            throw new BusinessRuleException(
204	                "Password must contain at least one special character");
205	        }
206	    }
207	
208	    private void recordFailedAttempt(String username, String ipAddress, String reason) {
209	        LoginAttempt attempt = new LoginAttempt();
210	        attempt.setUsername(username);
211	        attempt.setIpAddress(ipAddress);
212	        attempt.setSuccess(false);
213	        attempt.setFailureReason(reason);
214	        attempt.setAttemptedAt(LocalDateTime.now());
215	        loginAttemptRepository.save(attempt);
216	    }
217	
218	    private String hashToken(String token) {
219	        try {
220	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
221	            byte[] hash = digest.digest(token.getBytes(StandardCharsets.UTF_8));
222	            return HexFormat.of().formatHex(hash);
223	        } catch (NoSuchAlgorithmException e) {
224	            throw new IllegalStateException("SHA-256 not available", e);
225	        }
226	    }
227	}
