1	package com.reclaim.portal.auth.filter;
2	
3	import com.reclaim.portal.auth.service.CustomUserDetailsService;
4	import com.reclaim.portal.auth.service.JwtService;
5	import jakarta.servlet.FilterChain;
6	import jakarta.servlet.ServletException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import jakarta.servlet.http.HttpServletResponse;
9	import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
10	import org.springframework.security.core.context.SecurityContextHolder;
11	import org.springframework.security.core.userdetails.UserDetails;
12	import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
13	import org.springframework.stereotype.Component;
14	import org.springframework.web.filter.OncePerRequestFilter;
15	
16	import java.io.IOException;
17	
18	@Component("jwtAuthenticationFilter")
19	public class JwtAuthenticationFilter extends OncePerRequestFilter {
20	
21	    private final JwtService jwtService;
22	    private final CustomUserDetailsService customUserDetailsService;
23	
24	    public JwtAuthenticationFilter(JwtService jwtService,
25	                                   CustomUserDetailsService customUserDetailsService) {
26	        this.jwtService = jwtService;
27	        this.customUserDetailsService = customUserDetailsService;
28	    }
29	
30	    @Override
31	    protected boolean shouldNotFilter(HttpServletRequest request) {
32	        String path = request.getServletPath();
33	        return path.equals("/api/auth/login")
34	            || path.equals("/api/auth/refresh")
35	            || path.equals("/api/auth/logout")
36	            || path.equals("/login")
37	            || path.equals("/auth/change-password")
38	            || path.startsWith("/css/")
39	            || path.startsWith("/js/")
40	            || path.startsWith("/images/");
41	    }
42	
43	    @Override
44	    protected void doFilterInternal(HttpServletRequest request,
45	                                    HttpServletResponse response,
46	                                    FilterChain filterChain)
47	            throws ServletException, IOException {
48	
49	        String authHeader = request.getHeader("Authorization");
50	        String token = null;
51	
52	        if (authHeader != null && authHeader.startsWith("Bearer ")) {
53	            token = authHeader.substring(7);
54	        }
55	
56	        // Fallback: read access token from cookie (for Thymeleaf page navigations)
57	        if (token == null && request.getCookies() != null) {
58	            for (jakarta.servlet.http.Cookie cookie : request.getCookies()) {
59	                if ("accessToken".equals(cookie.getName())
60	                        && cookie.getValue() != null
61	                        && !cookie.getValue().isBlank()) {
62	                    token = cookie.getValue();
63	                    break;
64	                }
65	            }
66	        }
67	
68	        if (token != null && jwtService.isTokenValid(token)
69	                && SecurityContextHolder.getContext().getAuthentication() == null) {
70	            String username = jwtService.extractUsername(token);
71	            UserDetails userDetails = customUserDetailsService.loadUserByUsername(username);
72	            UsernamePasswordAuthenticationToken authToken =
73	                new UsernamePasswordAuthenticationToken(
74	                    userDetails,
75	                    null,
76	                    userDetails.getAuthorities()
77	                );
78	            authToken.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
79	            SecurityContextHolder.getContext().setAuthentication(authToken);
80	        }
81	
82	        filterChain.doFilter(request, response);
83	    }
84	}
