127	    @Test
128	    void shouldRefreshTokenSuccessfully() throws Exception {
129	        // Generate and store a refresh token, then sleep >1s so the next generated
130	        // token has a different issuedAt timestamp (JWT issuedAt has second precision)
131	        // avoiding the unique hash constraint violation on refresh_tokens
132	        String refreshTokenStr = jwtService.generateRefreshToken(testUser);
133	        String tokenHash = sha256Hex(refreshTokenStr);
134	
135	        RefreshToken stored = new RefreshToken();
136	        stored.setUserId(testUser.getId());
137	        stored.setTokenHash(tokenHash);
138	        stored.setExpiresAt(LocalDateTime.now().plusDays(7));
139	        stored.setRevoked(false);
140	        stored.setCreatedAt(LocalDateTime.now());
141	        refreshTokenRepository.saveAndFlush(stored);
142	
143	        // Refresh tokens now include a UUID jti, so no sleep needed for uniqueness
144	        AuthResponse refreshResponse = authService.refresh(refreshTokenStr);
145	
146	        assertThat(refreshResponse).isNotNull();
147	        assertThat(refreshResponse.getAccessToken()).isNotBlank();
148	        assertThat(refreshResponse.getRefreshToken()).isNotBlank();
149	    }
