151	    private String sha256Hex(String input) throws Exception {
152	        MessageDigest digest = MessageDigest.getInstance("SHA-256");
153	        byte[] hash = digest.digest(input.getBytes(StandardCharsets.UTF_8));
154	        return HexFormat.of().formatHex(hash);
155	    }
