2	
3	import com.reclaim.portal.auth.filter.JwtAuthenticationFilter;
4	import jakarta.servlet.http.HttpServletResponse;
5	import org.springframework.context.annotation.Bean;
6	import org.springframework.context.annotation.Configuration;
7	import org.springframework.security.authentication.AuthenticationManager;
8	import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
9	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
10	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
11	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
12	import org.springframework.security.config.http.SessionCreationPolicy;
13	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
14	import org.springframework.security.crypto.password.PasswordEncoder;
15	import org.springframework.security.web.SecurityFilterChain;
16	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
17	
18	@Configuration
19	@EnableWebSecurity
20	@EnableMethodSecurity
21	public class SecurityConfig {
22	
23	    private final JwtAuthenticationFilter jwtAuthenticationFilter;
24	
25	    public SecurityConfig(JwtAuthenticationFilter jwtAuthenticationFilter) {
26	        this.jwtAuthenticationFilter = jwtAuthenticationFilter;
27	    }
28	
29	    @Bean
30	    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
31	        // CSRF: The access token is delivered as an HttpOnly cookie for SSR page
32	        // compatibility, so mutable endpoints are cookie-authenticated. CSRF protection
33	        // is enabled using a cookie-based token repository. The XSRF-TOKEN cookie is
34	        // JS-readable so apiFetch can include it in the X-XSRF-TOKEN header.
35	        // Auth endpoints (login/refresh/logout) are excluded because they use a separate
36	        // refresh cookie with SameSite=Strict + Origin validation.
37	        http
38	            .csrf(csrf -> csrf
39	                .csrfTokenRepository(org.springframework.security.web.csrf.CookieCsrfTokenRepository.withHttpOnlyFalse())
40	                .ignoringRequestMatchers(
41	                    "/api/auth/login",
42	                    "/api/auth/refresh",
43	                    "/api/auth/logout"
44	                )
45	            )
46	            .sessionManagement(session ->
47	                session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
48	            .exceptionHandling(ex -> ex
49	                .authenticationEntryPoint((request, response, authException) -> {
50	                    response.setContentType("application/json");
51	                    response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
52	                    response.getWriter().write("{\"status\":401,\"error\":\"Unauthorized\",\"message\":\"Authentication required\"}");
53	                })
54	            )
55	            .authorizeHttpRequests(auth -> auth
56	                .requestMatchers(
57	                    "/api/auth/login",
58	                    "/api/auth/refresh",
59	                    "/api/auth/logout",
60	                    "/login",
61	                    "/auth/change-password",
62	                    "/css/**",
63	                    "/js/**",
64	                    "/images/**"
65	                ).permitAll()
66	                .requestMatchers("/api/admin/**", "/admin/**").hasRole("ADMIN")
67	                .requestMatchers("/api/reviewer/**", "/reviewer/**")
68	                    .hasAnyRole("REVIEWER", "ADMIN")
69	                .anyRequest().authenticated()
70	            )
71	            .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);
72	
73	        return http.build();
74	    }
75	
76	    @Bean
77	    public PasswordEncoder passwordEncoder() {
78	        return new BCryptPasswordEncoder();
79	    }
80	
81	    @Bean
82	    public AuthenticationManager authenticationManager(AuthenticationConfiguration config)
83	            throws Exception {
84	        return config.getAuthenticationManager();
85	    }
86	}
