1	package com.reclaim.portal.search.service;
2	
3	import com.reclaim.portal.catalog.entity.RecyclingItem;
4	import com.reclaim.portal.catalog.entity.SellerMetrics;
5	import com.reclaim.portal.catalog.repository.SellerMetricsRepository;
6	import com.reclaim.portal.orders.entity.Order;
7	import com.reclaim.portal.orders.entity.OrderItem;
8	import com.reclaim.portal.orders.repository.OrderItemRepository;
9	import com.reclaim.portal.orders.repository.OrderRepository;
10	import com.reclaim.portal.reviews.entity.Review;
11	import com.reclaim.portal.reviews.repository.ReviewRepository;
12	import com.reclaim.portal.search.entity.RankingStrategyVersion;
13	import com.reclaim.portal.search.entity.SearchLog;
14	import com.reclaim.portal.search.repository.RankingStrategyVersionRepository;
15	import com.reclaim.portal.search.repository.SearchClickLogRepository;
16	import com.reclaim.portal.search.repository.SearchLogRepository;
17	import org.slf4j.Logger;
18	import org.slf4j.LoggerFactory;
19	import org.springframework.stereotype.Service;
20	import org.springframework.transaction.annotation.Transactional;
21	
22	import java.math.BigDecimal;
23	import java.math.RoundingMode;
24	import java.util.ArrayList;
25	import java.util.Comparator;
26	import java.util.HashSet;
27	import java.util.List;
28	import java.util.Optional;
29	import java.util.Set;
30	import java.util.stream.Collectors;
31	
32	@Service
33	@Transactional(readOnly = true)
34	public class RankingService {
35	
36	    private static final Logger log = LoggerFactory.getLogger(RankingService.class);
37	
38	    private final RankingStrategyVersionRepository rankingStrategyVersionRepository;
39	    private final SellerMetricsRepository sellerMetricsRepository;
40	    private final SearchClickLogRepository clickLogRepository;
41	    private final SearchLogRepository searchLogRepository;
42	    private final OrderRepository orderRepository;
43	    private final OrderItemRepository orderItemRepository;
44	    private final ReviewRepository reviewRepository;
45	
46	    public RankingService(RankingStrategyVersionRepository rankingStrategyVersionRepository,
47	                          SellerMetricsRepository sellerMetricsRepository,
48	                          SearchClickLogRepository clickLogRepository,
49	                          SearchLogRepository searchLogRepository,
50	                          OrderRepository orderRepository,
51	                          OrderItemRepository orderItemRepository,
52	                          ReviewRepository reviewRepository) {
53	        this.rankingStrategyVersionRepository = rankingStrategyVersionRepository;
54	        this.sellerMetricsRepository = sellerMetricsRepository;
55	        this.clickLogRepository = clickLogRepository;
56	        this.searchLogRepository = searchLogRepository;
57	        this.orderRepository = orderRepository;
58	        this.orderItemRepository = orderItemRepository;
59	        this.reviewRepository = reviewRepository;
60	    }
61	
62	    public List<RecyclingItem> rankItems(List<RecyclingItem> items) {
63	        return rankItems(items, null);
64	    }
65	
66	    public List<RecyclingItem> rankItems(List<RecyclingItem> items, Long userId) {
67	        Optional<RankingStrategyVersion> strategyOpt = rankingStrategyVersionRepository.findByActiveTrue();
68	        if (strategyOpt.isEmpty()) {
69	            return items;
70	        }
71	
72	        RankingStrategyVersion strategy = strategyOpt.get();
73	        BigDecimal creditScoreWeight = orZero(strategy.getCreditScoreWeight());
74	        BigDecimal positiveRateWeight = orZero(strategy.getPositiveRateWeight());
75	        BigDecimal reviewQualityWeight = orZero(strategy.getReviewQualityWeight());
76	        BigDecimal minCreditScore = strategy.getMinCreditScoreThreshold();
77	        BigDecimal minPositiveRate = strategy.getMinPositiveRateThreshold();
78	
79	        // Build category affinity from user's completed orders
80	        Set<String> affinityCategories = new HashSet<>();
81	        if (userId != null) {
82	            List<Order> completed = orderRepository.findByUserId(userId).stream()
83	                .filter(o -> "COMPLETED".equals(o.getOrderStatus()))
84	                .toList();
85	            for (Order o : completed) {
86	                orderItemRepository.findByOrderId(o.getId()).stream()
87	                    .map(OrderItem::getSnapshotCategory)
88	                    .filter(c -> c != null)
89	                    .forEach(affinityCategories::add);
90	            }
91	        }
92	
93	        // Build recent-search keyword set from user's last 20 searches
94	        Set<String> recentSearchKeywords = new HashSet<>();
95	        if (userId != null) {
96	            List<SearchLog> recentSearches = searchLogRepository.findTop20ByUserIdOrderBySearchedAtDesc(userId);
97	            for (SearchLog sl : recentSearches) {
98	                if (sl.getSearchTerm() != null && !sl.getSearchTerm().isBlank()) {
99	                    recentSearchKeywords.add(sl.getSearchTerm().toLowerCase());
100	                }
101	            }
102	        }
103	
104	        List<ScoredItem> qualifiedItems = new ArrayList<>();
105	        List<RecyclingItem> noSellerItems = new ArrayList<>();
106	
107	        for (RecyclingItem item : items) {
108	            if (item.getSellerId() == null) {
109	                noSellerItems.add(item);
110	                continue;
111	            }
112	
113	            Optional<SellerMetrics> metricsOpt = sellerMetricsRepository.findBySellerId(item.getSellerId());
114	            if (metricsOpt.isEmpty()) {
115	                noSellerItems.add(item);
116	                continue;
117	            }
118	
119	            SellerMetrics metrics = metricsOpt.get();
120	            BigDecimal creditScore = orZero(metrics.getCreditScore());
121	            BigDecimal positiveRate = orZero(metrics.getPositiveRate());
122	            BigDecimal reviewQuality = orZero(metrics.getRecentReviewQuality());
123	
124	            // Filter items below thresholds
125	            if (minCreditScore != null && creditScore.compareTo(minCreditScore) < 0) {
126	                continue;
127	            }
128	            if (minPositiveRate != null && positiveRate.compareTo(minPositiveRate) < 0) {
129	                continue;
130	            }
131	
132	            // score = creditScore*weight + positiveRate*100*weight + recentReviewQuality*weight
133	            BigDecimal score = creditScore.multiply(creditScoreWeight)
134	                    .add(positiveRate.multiply(BigDecimal.valueOf(100)).multiply(positiveRateWeight))
135	                    .add(reviewQuality.multiply(reviewQualityWeight));
136	
137	            // Apply local behavior signal: boost items with more clicks (log scale to avoid domination)
138	            long clicks = clickLogRepository.countByItemId(item.getId());
139	            score = score.add(BigDecimal.valueOf(Math.log1p(clicks) * 0.5));
140	
141	            // Category affinity: boost items in categories the user has completed orders for
142	            if (affinityCategories.contains(item.getCategory())) {
143	                score = score.add(BigDecimal.valueOf(2.0));
144	            }
145	
146	            // Recent-search recency boost: if item title/category matches recent search keywords
147	            score = score.add(computeRecentSearchBoost(item, recentSearchKeywords));
148	
149	            // Review sentiment signal: adjust based on seller's review rating distribution
150	            score = score.add(computeReviewSentimentSignal(item.getSellerId()));
151	
152	            qualifiedItems.add(new ScoredItem(item, score));
153	        }
154	
155	        qualifiedItems.sort(Comparator.comparing(ScoredItem::score).reversed());
156	
157	        // Sort no-seller items with affinity-matching ones first
158	        final Set<String> finalAffinityCategories = affinityCategories;
159	        noSellerItems.sort(Comparator.comparingInt(
160	            (RecyclingItem i) -> finalAffinityCategories.contains(i.getCategory()) ? 0 : 1));
161	
162	        List<RecyclingItem> ranked = new ArrayList<>(qualifiedItems.size() + noSellerItems.size());
163	        for (ScoredItem si : qualifiedItems) {
164	            ranked.add(si.item());
165	        }
166	        ranked.addAll(noSellerItems);
167	        return ranked;
168	    }
169	
170	    /**
171	     * Computes a recency boost based on whether the item's title or category
172	     * matches any of the user's recent search keywords. Each matching keyword
173	     * contributes a small boost (max 3.0 total).
174	     */
175	    public BigDecimal computeRecentSearchBoost(RecyclingItem item, Set<String> recentSearchKeywords) {
176	        if (recentSearchKeywords.isEmpty()) {
177	            return BigDecimal.ZERO;
178	        }
179	
180	        double boost = 0.0;
181	        String titleLower = item.getTitle() != null ? item.getTitle().toLowerCase() : "";
182	        String categoryLower = item.getCategory() != null ? item.getCategory().toLowerCase() : "";
183	
184	        for (String keyword : recentSearchKeywords) {
185	            if (titleLower.contains(keyword) || categoryLower.contains(keyword)) {
186	                boost += 1.0;
187	            }
188	        }
189	
190	        return BigDecimal.valueOf(Math.min(boost, 3.0));
191	    }
192	
193	    /**
194	     * Computes a review-sentiment signal from the seller's review rating distribution.
195	     * Uses the actual review data (not pre-aggregated metrics) to derive a sentiment score.
196	     * <ul>
197	     *   <li>Average rating >= 4.0: positive boost (up to +2.0)</li>
198	     *   <li>Average rating 3.0-4.0: neutral (0)</li>
199	     *   <li>Average rating < 3.0: penalty (down to -1.5)</li>
200	     * </ul>
201	     * Sellers with no reviews get no adjustment.
202	     */
203	    public BigDecimal computeReviewSentimentSignal(Long sellerId) {
204	        if (sellerId == null) {
205	            return BigDecimal.ZERO;
206	        }
207	
208	        List<Review> reviews = reviewRepository.findReviewsForSeller(sellerId);
209	        if (reviews.isEmpty()) {
210	            return BigDecimal.ZERO;
211	        }
212	
213	        double avgRating = reviews.stream()
214	                .mapToInt(Review::getRating)
215	                .average()
216	                .orElse(3.0);
217	
218	        long totalReviews = reviews.size();
219	        long positiveReviews = reviews.stream().filter(r -> r.getRating() >= 4).count();
220	        double positiveRatio = (double) positiveReviews / totalReviews;
221	
222	        // Combined sentiment: weighted average of rating-based and distribution-based signals
223	        double ratingSignal;
224	        if (avgRating >= 4.0) {
225	            ratingSignal = (avgRating - 4.0) * 2.0; // 0 to 2.0 for ratings 4.0-5.0
226	        } else if (avgRating >= 3.0) {
227	            ratingSignal = 0.0;
228	        } else {
229	            ratingSignal = (avgRating - 3.0) * 1.5; // -1.5 to 0 for ratings 1.0-3.0
230	        }
231	
232	        // Positive ratio boost: high positive ratio adds a small bonus
233	        double distributionSignal = (positiveRatio - 0.5) * 1.0; // -0.5 to 0.5
234	
235	        // Scale by log of review count to give more weight to sellers with more reviews
236	        double confidenceScale = Math.min(Math.log1p(totalReviews) / 3.0, 1.0);
237	
238	        return BigDecimal.valueOf((ratingSignal + distributionSignal) * confidenceScale)
239	                .setScale(4, RoundingMode.HALF_UP);
240	    }
241	
242	    private BigDecimal orZero(BigDecimal value) {
243	        return value == null ? BigDecimal.ZERO : value;
244	    }
245	
246	    private record ScoredItem(RecyclingItem item, BigDecimal score) {
247	    }
248	}
