30	@Service
31	@Transactional
32	public class AdminService {
33	
34	    /** Simple projection for top-clicked item data used in analytics view. */
35	    public record ClickedItemSummary(Long itemId, String itemName, long clickCount) {}
36	
37	    private static final Logger log = LoggerFactory.getLogger(AdminService.class);
38	
39	    private final RankingStrategyVersionRepository strategyRepository;
40	    private final SearchLogRepository searchLogRepository;
