46	    public AdminService(RankingStrategyVersionRepository strategyRepository,
47	                        SearchLogRepository searchLogRepository,
48	                        SearchTrendRepository searchTrendRepository,
49	                        SearchClickLogRepository searchClickLogRepository,
50	                        AdminAccessLogRepository accessLogRepository,
51	                        RecyclingItemRepository recyclingItemRepository) {
52	        this.strategyRepository = strategyRepository;
53	        this.searchLogRepository = searchLogRepository;
54	        this.searchTrendRepository = searchTrendRepository;
55	        this.searchClickLogRepository = searchClickLogRepository;
56	        this.accessLogRepository = accessLogRepository;
57	        this.recyclingItemRepository = recyclingItemRepository;
58	    }
59	
60	    /**
61	     * Creates a new (inactive) ranking strategy version.
62	     */
63	    public RankingStrategyVersion createRankingStrategy(String versionLabel,
64	                                                        BigDecimal creditScoreWeight,
65	                                                        BigDecimal positiveRateWeight,
66	                                                        BigDecimal reviewQualityWeight,
67	                                                        BigDecimal minCreditScoreThreshold,
68	                                                        BigDecimal minPositiveRateThreshold,
69	                                                        Long createdBy) {
70	        RankingStrategyVersion strategy = new RankingStrategyVersion();
71	        strategy.setVersionLabel(versionLabel);
72	        strategy.setCreditScoreWeight(creditScoreWeight);
73	        strategy.setPositiveRateWeight(positiveRateWeight);
74	        strategy.setReviewQualityWeight(reviewQualityWeight);
75	        strategy.setMinCreditScoreThreshold(minCreditScoreThreshold);
76	        strategy.setMinPositiveRateThreshold(minPositiveRateThreshold);
77	        strategy.setActive(false);
78	        strategy.setCreatedBy(createdBy);
79	        strategy.setCreatedAt(LocalDateTime.now());
80	        return strategyRepository.save(strategy);
81	    }
82	
83	    /**
84	     * Deactivates all strategies, then activates the specified one.
85	     * Logs the activation in AdminAccessLog.
86	     */
87	    public RankingStrategyVersion activateStrategy(Long strategyId, Long adminUserId) {
88	        RankingStrategyVersion target = strategyRepository.findById(strategyId)
89	                .orElseThrow(() -> new EntityNotFoundException("RankingStrategyVersion", strategyId));
90	
91	        // Deactivate all existing active strategies
92	        List<RankingStrategyVersion> all = strategyRepository.findAllByOrderByCreatedAtDesc();
93	        for (RankingStrategyVersion s : all) {
94	            if (s.isActive()) {
95	                s.setActive(false);
96	                strategyRepository.save(s);
97	            }
98	        }
99	
100	        // Activate the target
101	        target.setActive(true);
102	        RankingStrategyVersion activated = strategyRepository.save(target);
103	
104	        // Log the action
105	        AdminAccessLog log = new AdminAccessLog();
106	        log.setAdminUserId(adminUserId);
107	        log.setActionType("STRATEGY_ACTIVATE");
108	        log.setTargetEntity("RankingStrategyVersion");
109	        log.setTargetId(strategyId);
110	        log.setReason("Strategy activation");
111	        log.setCreatedAt(LocalDateTime.now());
112	        accessLogRepository.save(log);
113	
114	        return activated;
115	    }
