134	    /**
135	     * Returns search analytics:
136	     * - totalSearches (count)
137	     * - totalClicks (count)
138	     * - uniqueKeywords (distinct search terms count)
139	     * - topTerms (top 10 trends by search count)
140	     * - topClickedItems (top 10 items by click count)
141	     * - recentSearches (last 20 search log entries)
142	     */
143	    @Transactional(readOnly = true)
144	    public Map<String, Object> getSearchAnalytics() {
145	        long totalSearches = searchLogRepository.count();
146	
147	        List<SearchClickLog> allClicks = searchClickLogRepository.findAll();
148	        long totalClicks = allClicks.size();
149	
150	        // Count distinct non-null search terms from trends table
151	        long uniqueKeywords = searchTrendRepository.count();
152	
153	        List<SearchTrend> topTerms = searchTrendRepository.findTop10ByOrderBySearchCountDesc();
154	
155	        // Compute top clicked items by grouping click logs, resolve item names
156	        Map<Long, Long> clicksPerItem = allClicks.stream()
157	                .filter(c -> c.getItemId() != null)
158	                .collect(Collectors.groupingBy(SearchClickLog::getItemId, Collectors.counting()));
159	
160	        // Collect IDs for the top 10
161	        List<Long> topItemIds = clicksPerItem.entrySet().stream()
162	                .sorted(Map.Entry.<Long, Long>comparingByValue(Comparator.reverseOrder()))
163	                .limit(10)
164	                .map(Map.Entry::getKey)
165	                .toList();
166	
167	        // Batch-resolve item names
168	        Map<Long, String> itemNames = recyclingItemRepository.findAllById(topItemIds).stream()
169	                .collect(Collectors.toMap(RecyclingItem::getId, RecyclingItem::getTitle));
170	
171	        List<ClickedItemSummary> topClickedItems = topItemIds.stream()
172	                .map(id -> new ClickedItemSummary(
173	                        id,
174	                        itemNames.getOrDefault(id, "Unknown Item #" + id),
175	                        clicksPerItem.get(id)))
176	                .collect(Collectors.toList());
177	
178	        // Compute clicks with linked search sessions (clicks that have searchLogId)
179	        long clicksWithSearchContext = allClicks.stream()
180	                .filter(c -> c.getSearchLogId() != null)
181	                .count();
182	
183	        List<SearchLog> recentSearches = searchLogRepository.findAll().stream()
184	                .sorted((a, b) -> {
185	                    if (a.getSearchedAt() == null && b.getSearchedAt() == null) return 0;
186	                    if (a.getSearchedAt() == null) return 1;
187	                    if (b.getSearchedAt() == null) return -1;
188	                    return b.getSearchedAt().compareTo(a.getSearchedAt());
189	                })
190	                .limit(20)
191	                .toList();
192	
193	        Map<String, Object> analytics = new LinkedHashMap<>();
194	        analytics.put("totalSearches", totalSearches);
195	        analytics.put("totalClicks", totalClicks);
196	        analytics.put("clicksWithSearchContext", clicksWithSearchContext);
197	        analytics.put("uniqueKeywords", uniqueKeywords);
198	        analytics.put("topTerms", topTerms);
199	        analytics.put("topClickedItems", topClickedItems);
200	        analytics.put("recentSearches", recentSearches);
201	
202	        // Daily search trend: aggregate from search_trends table
203	        List<Map<String, Object>> searchTrend = searchTrendRepository.findTop10ByOrderBySearchCountDesc()
204	                .stream()
205	                .map(t -> {
206	                    Map<String, Object> entry = new LinkedHashMap<>();
207	                    entry.put("date", t.getPeriodStart() != null ? t.getPeriodStart().toString() : "—");
208	                    entry.put("count", t.getSearchCount());
209	                    return entry;
210	                })
211	                .toList();
212	        analytics.put("searchTrend", searchTrend);
213	
214	        return analytics;
215	    }
216	
