218	     * Returns all admin access logs ordered by createdAt descending.
219	     */
220	    @Transactional(readOnly = true)
221	    public List<AdminAccessLog> getAccessLogs() {
222	        return accessLogRepository.findAll().stream()
223	                .sorted((a, b) -> {
224	                    if (a.getCreatedAt() == null && b.getCreatedAt() == null) return 0;
225	                    if (a.getCreatedAt() == null) return 1;
226	                    if (b.getCreatedAt() == null) return -1;
227	                    return b.getCreatedAt().compareTo(a.getCreatedAt());
228	                })
229	                .toList();
230	    }
