3	import com.reclaim.portal.appointments.entity.Appointment;
4	import com.reclaim.portal.appointments.service.AppointmentService;
5	import com.reclaim.portal.catalog.entity.RecyclingItem;
6	import com.reclaim.portal.catalog.repository.RecyclingItemRepository;
7	import com.reclaim.portal.common.exception.BusinessRuleException;
8	import com.reclaim.portal.common.exception.EntityNotFoundException;
9	import com.reclaim.portal.orders.entity.Order;
10	import com.reclaim.portal.orders.entity.OrderItem;
11	import com.reclaim.portal.orders.entity.OrderOperationLog;
12	import com.reclaim.portal.orders.repository.OrderItemRepository;
13	import com.reclaim.portal.orders.repository.OrderOperationLogRepository;
14	import com.reclaim.portal.orders.repository.OrderRepository;
15	import org.slf4j.Logger;
16	import org.slf4j.LoggerFactory;
17	import org.springframework.stereotype.Service;
18	import org.springframework.transaction.annotation.Transactional;
19	
20	import java.math.BigDecimal;
21	import java.time.LocalDateTime;
22	import java.time.LocalTime;
23	import java.time.format.DateTimeFormatter;
24	import java.util.ArrayList;
25	import java.util.List;
26	import java.util.Map;
27	
28	@Service
29	@Transactional
30	public class OrderService {
31	
32	    private static final Logger log = LoggerFactory.getLogger(OrderService.class);
33	    private static final DateTimeFormatter TIME_FMT = DateTimeFormatter.ofPattern("HH:mm");
34	
35	    private static final String STATUS_PENDING = "PENDING_CONFIRMATION";
36	    private static final String STATUS_ACCEPTED = "ACCEPTED";
37	    private static final String STATUS_COMPLETED = "COMPLETED";
38	    private static final String STATUS_CANCELED = "CANCELED";
39	    private static final String STATUS_EXCEPTION = "EXCEPTION";
40	
41	    private final OrderRepository orderRepository;
42	    private final OrderItemRepository orderItemRepository;
43	    private final OrderOperationLogRepository orderOperationLogRepository;
44	    private final AppointmentService appointmentService;
45	    private final RecyclingItemRepository recyclingItemRepository;
46	
47	    public OrderService(OrderRepository orderRepository,
48	                        OrderItemRepository orderItemRepository,
49	                        OrderOperationLogRepository orderOperationLogRepository,
50	                        AppointmentService appointmentService,
51	                        RecyclingItemRepository recyclingItemRepository) {
52	        this.orderRepository = orderRepository;
53	        this.orderItemRepository = orderItemRepository;
54	        this.orderOperationLogRepository = orderOperationLogRepository;
55	        this.appointmentService = appointmentService;
56	        this.recyclingItemRepository = recyclingItemRepository;
57	    }
58	
59	    /**
60	     * Create a new order: validate appointment, book slot, snapshot items, calculate total.
61	     */
62	    public Order createOrder(Long userId, List<Long> itemIds, Long appointmentId, String appointmentType) {
63	        // Validate appointment exists and has capacity
64	        Appointment appointment = appointmentService.findById(appointmentId);
65	        if (!appointmentType.equals(appointment.getAppointmentType())) {
66	            throw new BusinessRuleException(
67	                "Appointment type mismatch: expected " + appointment.getAppointmentType()
68	                    + " but got " + appointmentType);
69	        }
70	        appointmentService.validateAppointmentTime(
71	            appointment.getAppointmentDate(), appointment.getStartTime());
72	
73	        // Book the slot (throws if no capacity)
74	        appointmentService.bookSlot(appointmentId);
75	
76	        // Create order
77	        LocalDateTime now = LocalDateTime.now();
78	        Order order = new Order();
79	        order.setUserId(userId);
80	        order.setAppointmentId(appointmentId);
81	        order.setOrderStatus(STATUS_PENDING);
82	        order.setAppointmentType(appointmentType);
83	        order.setRescheduleCount(0);
84	        order.setCurrency("USD");
85	        order.setCreatedAt(now);
86	        order.setUpdatedAt(now);
87	        order = orderRepository.save(order);
88	
89	        // Snapshot items
90	        List<RecyclingItem> items = recyclingItemRepository.findAllById(itemIds);
91	        if (items.isEmpty()) {
92	            throw new BusinessRuleException("No valid items found for the provided item ids");
93	        }
94	
95	        BigDecimal total = BigDecimal.ZERO;
96	        List<OrderItem> orderItems = new ArrayList<>();
97	        for (RecyclingItem item : items) {
98	            OrderItem oi = new OrderItem();
99	            oi.setOrderId(order.getId());
100	            oi.setItemId(item.getId());
101	            oi.setSnapshotTitle(item.getTitle());
102	            oi.setSnapshotCategory(item.getCategory());
103	            oi.setSnapshotCondition(item.getItemCondition());
104	            oi.setSnapshotPrice(item.getPrice() != null ? item.getPrice() : BigDecimal.ZERO);
105	            orderItems.add(oi);
106	            if (item.getPrice() != null) {
107	                total = total.add(item.getPrice());
108	            }
109	        }
110	        orderItemRepository.saveAll(orderItems);
111	
112	        order.setTotalPrice(total);
113	        order = orderRepository.save(order);
114	
115	        logOperation(order.getId(), userId, "ORDER_CREATED", null, STATUS_PENDING,
116	            "Order created with " + items.size() + " item(s)");
117	        log.info("Order created: id={}, userId={}, items={}", order.getId(), userId, items.size());
118	
119	        return order;
120	    }
121	
122	    /**
123	     * Accept a pending order: PENDING_CONFIRMATION -> ACCEPTED.
124	     */
125	    public Order acceptOrder(Long orderId, Long reviewerId) {
126	        Order order = findOrderById(orderId);
127	        requireStatus(order, STATUS_PENDING);
128	
129	        String prev = order.getOrderStatus();
130	        order.setOrderStatus(STATUS_ACCEPTED);
131	        order.setReviewerId(reviewerId);
132	        order.setUpdatedAt(LocalDateTime.now());
133	        order = orderRepository.save(order);
134	
135	        logOperation(orderId, reviewerId, "ORDER_ACCEPTED", prev, STATUS_ACCEPTED, null);
136	        return order;
137	    }
138	
139	    /**
140	     * Complete an accepted order: ACCEPTED -> COMPLETED.
141	     */
142	    public Order completeOrder(Long orderId, Long actorId) {
143	        Order order = findOrderById(orderId);
144	        requireStatus(order, STATUS_ACCEPTED);
145	
146	        String prev = order.getOrderStatus();
147	        order.setOrderStatus(STATUS_COMPLETED);
148	        order.setUpdatedAt(LocalDateTime.now());
149	        order = orderRepository.save(order);
150	
151	        logOperation(orderId, actorId, "ORDER_COMPLETED", prev, STATUS_COMPLETED, null);
152	        return order;
153	    }
154	
155	    /**
156	     * Cancel an order. If the appointment is less than 1 hour away, flag as EXCEPTION instead.
157	     * Only the order owner may request cancellation.
158	     */
159	    public Order cancelOrder(Long orderId, Long actorId, String reason) {
160	        Order order = findOrderById(orderId);
161	        if (actorId == null || !actorId.equals(order.getUserId())) {
162	            throw new BusinessRuleException("Access denied");
163	        }
164	        if (!STATUS_PENDING.equals(order.getOrderStatus())
165	                && !STATUS_ACCEPTED.equals(order.getOrderStatus())) {
166	            throw new BusinessRuleException(
167	                "Cannot cancel order in status: " + order.getOrderStatus());
168	        }
169	
170	        // Determine if appointment is < 1 hr away
171	        Appointment appointment = appointmentService.findById(order.getAppointmentId());
172	        LocalTime startTime = LocalTime.parse(appointment.getStartTime(), TIME_FMT);
173	        LocalDateTime appointmentDateTime = appointment.getAppointmentDate().atTime(startTime);
174	        LocalDateTime now = LocalDateTime.now();
175	        boolean tooClose = appointmentDateTime.isBefore(now.plusHours(1));
176	
177	        String prev = order.getOrderStatus();
178	
179	        if (tooClose) {
180	            // Flag as exception - requires admin approval to proceed
181	            order.setOrderStatus(STATUS_EXCEPTION);
182	            order.setCancellationReason(reason);
183	            order.setUpdatedAt(now);
184	            order = orderRepository.save(order);
185	            logOperation(orderId, actorId, "CANCEL_REQUESTED", prev, STATUS_EXCEPTION,
186	                "Cancellation requested within 1 hour of appointment: " + reason);
187	        } else {
188	            order.setOrderStatus(STATUS_CANCELED);
189	            order.setCancellationReason(reason);
190	            order.setUpdatedAt(now);
191	            order = orderRepository.save(order);
192	            appointmentService.releaseSlot(order.getAppointmentId());
193	            logOperation(orderId, actorId, "ORDER_CANCELED", prev, STATUS_CANCELED, reason);
194	        }
195	
196	        return order;
197	    }
198	
199	    /**
200	     * Approve a cancellation that was flagged as EXCEPTION: EXCEPTION -> CANCELED.
201	     */
202	    public Order approveCancellation(Long orderId, Long reviewerId, String reason) {
203	        Order order = findOrderById(orderId);
204	        requireStatus(order, STATUS_EXCEPTION);
205	
206	        String prev = order.getOrderStatus();
207	        order.setOrderStatus(STATUS_CANCELED);
208	        order.setCancellationApprovedBy(reviewerId);
209	        order.setCancellationReason(reason != null ? reason : order.getCancellationReason());
210	        order.setUpdatedAt(LocalDateTime.now());
211	        order = orderRepository.save(order);
212	
213	        appointmentService.releaseSlot(order.getAppointmentId());
214	        logOperation(orderId, reviewerId, "CANCEL_APPROVED", prev, STATUS_CANCELED,
215	            "Cancellation approved by reviewer " + reviewerId);
216	
217	        return order;
218	    }
219	
220	    /**
221	     * Reschedule an order to a new appointment slot.
222	     * Requires: PENDING or ACCEPTED, rescheduleCount < 2.
223	     * Only the order owner may reschedule.
224	     */
225	    public Order rescheduleOrder(Long orderId, Long actorId, Long newAppointmentId) {
226	        Order order = findOrderById(orderId);
227	        if (actorId == null || !actorId.equals(order.getUserId())) {
228	            throw new BusinessRuleException("Access denied");
229	        }
230	        if (!STATUS_PENDING.equals(order.getOrderStatus())
231	                && !STATUS_ACCEPTED.equals(order.getOrderStatus())) {
232	            throw new BusinessRuleException(
233	                "Cannot reschedule order in status: " + order.getOrderStatus());
234	        }
235	        if (order.getRescheduleCount() >= 2) {
236	            throw new BusinessRuleException("Order has already been rescheduled the maximum number of times (2)");
237	        }
238	
239	        // Validate the new appointment
240	        Appointment newAppointment = appointmentService.findById(newAppointmentId);
241	        appointmentService.validateAppointmentTime(
242	            newAppointment.getAppointmentDate(), newAppointment.getStartTime());
243	
244	        // Appointment type must match the original order type (cannot switch pickup/drop-off)
245	        if (order.getAppointmentType() != null
246	                && !order.getAppointmentType().equals(newAppointment.getAppointmentType())) {
247	            throw new BusinessRuleException(
248	                "Cannot change appointment type during reschedule: order is "
249	                    + order.getAppointmentType() + " but new slot is "
250	                    + newAppointment.getAppointmentType());
251	        }
252	
253	        Long oldAppointmentId = order.getAppointmentId();
254	
255	        // Release old slot and book new one
256	        appointmentService.releaseSlot(oldAppointmentId);
257	        appointmentService.bookSlot(newAppointmentId);
258	
259	        String prev = order.getOrderStatus();
260	        order.setAppointmentId(newAppointmentId);
261	        order.setRescheduleCount(order.getRescheduleCount() + 1);
262	        order.setUpdatedAt(LocalDateTime.now());
263	        order = orderRepository.save(order);
264	
265	        logOperation(orderId, actorId, "ORDER_RESCHEDULED", prev, order.getOrderStatus(),
266	            "Rescheduled from appointment " + oldAppointmentId + " to " + newAppointmentId);
267	
268	        return order;
269	    }
