279	    }
280	
281	    /**
282	     * Authorization helper: verifies that the actor is allowed to access an order.
283	     * Staff (isStaff=true) may always access. Otherwise, actorId must equal the order owner.
284	     * Also allows the assigned reviewer to view.
285	     */
286	    public void requireOrderOwnerOrStaff(Order order, Long actorId, boolean isStaff) {
287	        if (isStaff) {
288	            return;
289	        }
290	        if (actorId != null && actorId.equals(order.getUserId())) {
291	            return;
292	        }
293	        if (actorId != null && actorId.equals(order.getReviewerId())) {
294	            return;
