299	    @Transactional(readOnly = true)
300	    public Map<String, Object> getOrderWithLogs(Long orderId, Long actorId, boolean isStaff) {
301	        Order order = findOrderById(orderId);
302	        if (!isStaff && (actorId == null || !actorId.equals(order.getUserId()))) {
