307	            .findByOrderIdOrderByCreatedAtAsc(orderId);
308	        return Map.of("order", order, "items", items, "logs", logs);
309	    }
310	
311	    /** Backward-compatible variant used by internal/test callers — no ownership check. */
312	    @Transactional(readOnly = true)
313	    public Map<String, Object> getOrderWithLogs(Long orderId) {
314	        Order order = findOrderById(orderId);
315	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
316	        List<OrderOperationLog> logs = orderOperationLogRepository
317	            .findByOrderIdOrderByCreatedAtAsc(orderId);
318	        return Map.of("order", order, "items", items, "logs", logs);
319	    }
