321	    @Transactional(readOnly = true)
322	    public Order findOrderById(Long orderId) {
323	        return orderRepository.findById(orderId)
324	            .orElseThrow(() -> new EntityNotFoundException("Order", orderId));
325	    }
326	
327	    private void requireStatus(Order order, String expectedStatus) {
328	        if (!expectedStatus.equals(order.getOrderStatus())) {
329	            throw new BusinessRuleException(
330	                "Expected order status " + expectedStatus + " but found " + order.getOrderStatus());
331	        }
332	    }
333	
334	    private void logOperation(Long orderId, Long actorId, String operation,
335	                               String previousStatus, String newStatus, String details) {
336	        OrderOperationLog log = new OrderOperationLog();
337	        log.setOrderId(orderId);
338	        log.setActorId(actorId);
339	        log.setOperation(operation);
340	        log.setPreviousStatus(previousStatus);
341	        log.setNewStatus(newStatus);
342	        log.setDetails(details);
343	        log.setCreatedAt(LocalDateTime.now());
344	        orderOperationLogRepository.save(log);
345	    }
