1	package com.reclaim.portal.auth.service;
2	
3	import com.reclaim.portal.auth.entity.Role;
4	import com.reclaim.portal.auth.entity.User;
5	import com.reclaim.portal.auth.repository.RoleRepository;
6	import com.reclaim.portal.auth.repository.UserRepository;
7	import com.reclaim.portal.common.config.ReclaimProperties;
8	import org.springframework.boot.ApplicationArguments;
9	import org.springframework.boot.ApplicationRunner;
10	import org.springframework.security.crypto.password.PasswordEncoder;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.io.IOException;
15	import java.nio.file.Files;
16	import java.nio.file.Path;
17	import java.time.LocalDateTime;
18	import java.util.HashMap;
19	import java.util.Map;
20	import java.util.Optional;
21	import java.util.Set;
22	
23	@Service
24	public class BootstrapService implements ApplicationRunner {
25	
26	    private static final Map<String, String> USER_ROLE_MAP = new HashMap<>();
27	
28	    static {
29	        USER_ROLE_MAP.put("admin", "ROLE_ADMIN");
30	        USER_ROLE_MAP.put("reviewer", "ROLE_REVIEWER");
31	        USER_ROLE_MAP.put("user", "ROLE_USER");
32	    }
33	
34	    private static final Map<String, String> USER_PASSWORD_KEY_MAP = new HashMap<>();
35	
36	    static {
37	        USER_PASSWORD_KEY_MAP.put("admin", "admin_password");
38	        USER_PASSWORD_KEY_MAP.put("reviewer", "reviewer_password");
39	        USER_PASSWORD_KEY_MAP.put("user", "user_password");
40	    }
41	
42	    private final UserRepository userRepository;
43	    private final RoleRepository roleRepository;
44	    private final PasswordEncoder passwordEncoder;
45	    private final ReclaimProperties reclaimProperties;
46	
47	    public BootstrapService(UserRepository userRepository,
48	                            RoleRepository roleRepository,
49	                            PasswordEncoder passwordEncoder,
50	                            ReclaimProperties reclaimProperties) {
51	        this.userRepository = userRepository;
52	        this.roleRepository = roleRepository;
53	        this.passwordEncoder = passwordEncoder;
54	        this.reclaimProperties = reclaimProperties;
55	    }
56	
57	    @Override
58	    @Transactional
59	    public void run(ApplicationArguments args) throws Exception {
60	        String passwordsFilePath = reclaimProperties.getBootstrap().getPasswordsFile();
61	        if (passwordsFilePath == null || passwordsFilePath.isBlank()) {
62	            return;
63	        }
64	
65	        Map<String, String> passwords = readPasswordsFile(passwordsFilePath);
66	
67	        for (Map.Entry<String, String> entry : USER_PASSWORD_KEY_MAP.entrySet()) {
68	            String username = entry.getKey();
69	            String passwordKey = entry.getValue();
70	
71	            if (!userRepository.existsByUsername(username)) {
72	                String rawPassword = passwords.get(passwordKey);
73	                if (rawPassword == null || rawPassword.isBlank()) {
74	                    continue;
75	                }
76	
77	                String roleName = USER_ROLE_MAP.get(username);
78	                Optional<Role> roleOpt = roleRepository.findByName(roleName);
79	                if (roleOpt.isEmpty()) {
80	                    continue;
81	                }
82	
83	                User user = new User();
84	                user.setUsername(username);
85	                user.setPasswordHash(passwordEncoder.encode(rawPassword));
86	                user.setEnabled(true);
87	                user.setLocked(false);
88	                user.setForcePasswordReset(true);
89	                user.setFailedAttempts(0);
90	                user.setCreatedAt(LocalDateTime.now());
91	                user.setUpdatedAt(LocalDateTime.now());
92	                user.setRoles(Set.of(roleOpt.get()));
93	
94	                userRepository.save(user);
95	            }
96	        }
97	    }
98	
99	    private Map<String, String> readPasswordsFile(String filePath) throws IOException {
100	        Map<String, String> result = new HashMap<>();
101	        Path path = Path.of(filePath);
102	        if (!Files.exists(path)) {
103	            return result;
104	        }
105	        for (String line : Files.readAllLines(path)) {
106	            line = line.trim();
107	            if (line.isEmpty() || line.startsWith("#")) {
108	                continue;
109	            }
110	            int idx = line.indexOf('=');
111	            if (idx > 0) {
112	                String key = line.substring(0, idx).trim();
113	                String value = line.substring(idx + 1).trim();
114	                result.put(key, value);
115	            }
116	        }
117	        return result;
118	    }
119	}
