1	package com.reclaim.portal.web;
2	
3	import com.reclaim.portal.storage.service.StorageService;
4	import org.junit.jupiter.api.BeforeEach;
5	import org.junit.jupiter.api.Test;
6	import org.junit.jupiter.api.io.TempDir;
7	import org.springframework.beans.factory.annotation.Autowired;
8	import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
9	import org.springframework.boot.test.context.SpringBootTest;
10	import org.springframework.http.MediaType;
11	import org.springframework.mock.web.MockMultipartFile;
12	import org.springframework.security.test.context.support.WithMockUser;
13	import org.springframework.test.context.ActiveProfiles;
14	import org.springframework.test.web.servlet.MockMvc;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.nio.file.Path;
18	
19	import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
20	import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
21	
22	/**
23	 * Tests for the StorageFileController that serves stored files (signatures, evidence).
24	 * Verifies that files can be retrieved, content types are correct,
25	 * and path traversal attempts are blocked.
26	 */
27	@SpringBootTest
28	@AutoConfigureMockMvc
29	@ActiveProfiles("test")
30	@Transactional
31	class StorageFileControllerTest {
32	
33	    @Autowired
34	    private MockMvc mockMvc;
35	
36	    @Autowired
37	    private StorageService storageService;
38	
39	    private String storedFilePath;
40	
41	    @BeforeEach
42	    void setUp() {
43	        // Store a minimal PNG signature file
44	        byte[] minimalPng = createMinimalPng();
45	        MockMultipartFile sigFile = new MockMultipartFile(
46	                "file", "test_signature.png", "image/png", minimalPng);
47	        var result = storageService.store(sigFile, "signatures");
48	        storedFilePath = result.filePath(); // e.g. "signatures/<uuid>.png"
49	    }
50	
51	    @Test
52	    @WithMockUser(username = "testuser", roles = {"ADMIN"})
53	    void shouldServeStoredFileWithCorrectContentType() throws Exception {
54	        // Admins can access any stored file (unrestricted for dispute resolution and audit)
55	        mockMvc.perform(get("/storage/" + storedFilePath))
56	               .andExpect(status().isOk())
57	               .andExpect(content().contentType(MediaType.IMAGE_PNG))
58	               .andExpect(header().exists("Content-Length"))
59	               .andExpect(header().exists("Cache-Control"));
60	    }
61	
62	    @Test
63	    @WithMockUser(username = "testuser", roles = {"ADMIN"})
64	    void shouldReturn404ForNonexistentFile() throws Exception {
65	        mockMvc.perform(get("/storage/signatures/nonexistent-file.png"))
66	               .andExpect(status().isNotFound());
67	    }
68	
69	    @Test
70	    @WithMockUser(username = "testuser", roles = {"USER"})
71	    void shouldDenyRegularUserAccessToUnownedSignature() throws Exception {
72	        // Regular user with no linked contract gets 403
73	        mockMvc.perform(get("/storage/" + storedFilePath))
74	               .andExpect(status().isForbidden());
75	    }
76	
77	    @Test
78	    @WithMockUser(username = "testuser", roles = {"USER"})
79	    void shouldBlockPathTraversalAttempts() throws Exception {
80	        // Spring's URL normalization rejects ".." paths with 400 before reaching the controller
81	        mockMvc.perform(get("/storage/../etc/passwd"))
82	               .andExpect(status().isBadRequest());
83	    }
84	
85	    @Test
86	    @WithMockUser(username = "testuser", roles = {"USER"})
87	    void shouldBlockPathTraversalInNestedPath() throws Exception {
88	        // Spring's URL normalization rejects ".." paths with 400 before reaching the controller
89	        mockMvc.perform(get("/storage/signatures/../../etc/shadow"))
90	               .andExpect(status().isBadRequest());
91	    }
92	
93	    @Test
94	    @WithMockUser(username = "testuser", roles = {"USER"})
95	    void shouldBlockEncodedPathTraversalAtService() throws Exception {
96	        // Even if someone encodes the "..", the StorageService blocks it
97	        // This tests the controller's handling of the BusinessRuleException from StorageService
98	        mockMvc.perform(get("/storage/..%2Fetc%2Fpasswd"))
99	               .andExpect(status().is4xxClientError());
100	    }
101	
102	    @Test
103	    void shouldRequireAuthenticationForStorageAccess() throws Exception {
104	        // No @WithMockUser — unauthenticated
105	        mockMvc.perform(get("/storage/" + storedFilePath))
106	               .andExpect(status().isUnauthorized());
107	    }
108	
109	    @Test
110	    @WithMockUser(username = "testuser", roles = {"ADMIN"})
111	    void shouldReturnImageDataMatchingOriginalSize() throws Exception {
112	        byte[] originalPng = createMinimalPng();
113	
114	        mockMvc.perform(get("/storage/" + storedFilePath))
115	               .andExpect(status().isOk())
116	               .andExpect(content().bytes(originalPng));
117	    }
118	
119	    private byte[] createMinimalPng() {
120	        return new byte[]{
121	            (byte) 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A,
122	            0x00, 0x00, 0x00, 0x0D, 0x49, 0x48, 0x44, 0x52,
123	            0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x00, 0x01,
124	            0x08, 0x02, 0x00, 0x00, 0x00, (byte) 0x90, 0x77, 0x53,
125	            (byte) 0xDE, 0x00, 0x00, 0x00, 0x0C, 0x49, 0x44, 0x41,
