585	    // ── Login form ───────────────────────────────────────────────────
586	    document.getElementById('loginForm').addEventListener('submit', async function (e) {
587	        e.preventDefault();
588	
589	        const username = document.getElementById('username').value.trim();
590	        const password = document.getElementById('password').value;
591	        const alertBox = document.getElementById('alertBox');
592	        const btn = document.getElementById('submitBtn');
593	
594	        alertBox.textContent = '';
595	        alertBox.classList.remove('visible');
596	
597	        if (!username || !password) {
598	            alertBox.textContent = 'Username and password are required.';
599	            alertBox.classList.add('visible');
600	            return;
601	        }
602	
603	        btn.classList.add('loading');
604	
605	        try {
606	            const res = await fetch('/api/auth/login', {
607	                method: 'POST',
608	                headers: { 'Content-Type': 'application/json' },
609	                credentials: 'same-origin',
610	                body: JSON.stringify({ username, password })
611	            });
612	
613	            if (res.ok) {
614	                const data = await res.json();
615	
616	                if (data.forcePasswordReset) {
617	                    window.location.href = '/auth/change-password';
618	                } else {
619	                    // Route based on role: decode JWT payload to check roles
620	                    let dest = '/user/dashboard';
621	                    try {
622	                        const payload = JSON.parse(atob(data.accessToken.split('.')[1]));
623	                        const roles = payload.roles || [];
624	                        if (roles.includes('ROLE_ADMIN')) dest = '/admin/dashboard';
625	                        else if (roles.includes('ROLE_REVIEWER')) dest = '/reviewer/dashboard';
626	                    } catch (_) {}
627	                    window.location.href = dest;
628	                }
629	                return;
630	            }
631	
632	            let message = 'Authentication failed.';
633	            try {
634	                const err = await res.json();
635	                if (err && (err.message || err.error)) {
636	                    message = err.message || err.error;
637	                }
638	            } catch (_) { /* ignore */ }
639	
640	            alertBox.textContent = message;
641	            alertBox.classList.add('visible');
642	            document.getElementById('password').value = '';
