10	/* ── Token management (in-memory only) ───────────────────────
11	   The access token is kept only in memory within the current
12	   page load. The HttpOnly accessToken cookie (set by the server
13	   on login/refresh) authenticates page navigations and API calls
14	   when the in-memory token is absent. JS must never read the
15	   cookie directly — it is HttpOnly.
16	   ─────────────────────────────────────────────────────────── */
17	const TokenStore = (() => {
18	    let _token = null;
19	
20	    function get() { return _token; }
21	
22	    function set(token) { _token = token; }
23	
24	    function clear() {
25	        _token = null;
26	        document.cookie = 'accessToken=; path=/; max-age=0; SameSite=Strict';
27	    }
28	
29	    return { get, set, clear };
30	})();
31	
32	/* ── Fetch wrapper ───────────────────────────────────────────
33	   Automatically attaches Authorization header when token exists.
34	   Handles 401 by redirecting to /login.
35	   ─────────────────────────────────────────────────────────── */
36	async function apiFetch(url, options = {}) {
37	    const token = TokenStore.get();
38	    const headers = Object.assign({}, options.headers || {});
39	
40	    if (token) {
41	        headers['Authorization'] = 'Bearer ' + token;
42	    }
43	
44	    if (!(options.body instanceof FormData) && !headers['Content-Type']) {
45	        if (options.body && typeof options.body === 'string') {
46	            headers['Content-Type'] = 'application/json';
47	        }
48	    }
49	
50	    // Include CSRF token from XSRF-TOKEN cookie (set by Spring CookieCsrfTokenRepository)
51	    const xsrfMatch = document.cookie.match(/(?:^|;\s*)XSRF-TOKEN=([^;]*)/);
52	    if (xsrfMatch) {
53	        headers['X-XSRF-TOKEN'] = decodeURIComponent(xsrfMatch[1]);
54	    }
55	
56	    const response = await fetch(url, Object.assign({}, options, { headers, credentials: 'same-origin' }));
57	
58	    if (response.status === 401) {
59	        TokenStore.clear();
60	        window.location.href = '/login';
61	        throw new Error('Unauthorized — redirecting to login');
62	    }
63	
64	    return response;
65	}
