81	/* ── Debounce ────────────────────────────────────────────────── */
82	function debounce(fn, ms) {
83	    let timer;
84	    return function (...args) {
85	        clearTimeout(timer);
86	        timer = setTimeout(() => fn.apply(this, args), ms);
87	    };
88	}
