90	/* ── Autocomplete ────────────────────────────────────────────── */
91	function initAutocomplete(inputEl, listEl, endpoint) {
92	    if (!inputEl || !listEl) return;
93	
94	    let activeIndex = -1;
95	
96	    const fetchSuggestions = debounce(async function (q) {
97	        if (!q || q.length < 2) {
98	            closeList();
99	            return;
100	        }
101	        try {
102	            const res = await apiFetch(`${endpoint}?q=${encodeURIComponent(q)}&limit=8`);
103	            if (!res.ok) { closeList(); return; }
104	            const suggestions = await res.json(); // expected: string[]
105	            renderList(suggestions, q);
106	        } catch (_) { closeList(); }
107	    }, 280);
108	
109	    inputEl.addEventListener('input', function () {
110	        activeIndex = -1;
111	        fetchSuggestions(this.value.trim());
112	    });
113	
114	    inputEl.addEventListener('keydown', function (e) {
115	        const items = listEl.querySelectorAll('.autocomplete-item');
116	        if (!items.length) return;
117	
118	        if (e.key === 'ArrowDown') {
119	            e.preventDefault();
120	            activeIndex = Math.min(activeIndex + 1, items.length - 1);
121	            highlightItem(items);
122	        } else if (e.key === 'ArrowUp') {
123	            e.preventDefault();
124	            activeIndex = Math.max(activeIndex - 1, 0);
125	            highlightItem(items);
126	        } else if (e.key === 'Enter' && activeIndex >= 0) {
127	            e.preventDefault();
128	            items[activeIndex].click();
129	        } else if (e.key === 'Escape') {
130	            closeList();
131	        }
132	    });
133	
134	    document.addEventListener('click', function (e) {
135	        if (!inputEl.contains(e.target) && !listEl.contains(e.target)) {
136	            closeList();
137	        }
138	    });
139	
140	    function highlightItem(items) {
141	        items.forEach((it, i) => it.classList.toggle('highlighted', i === activeIndex));
142	    }
143	
144	    function escHtml(str) {
145	        return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
146	    }
147	
148	    function renderList(suggestions, q) {
149	        listEl.innerHTML = '';
150	        if (!suggestions.length) { closeList(); return; }
151	        suggestions.forEach(s => {
152	            const div = document.createElement('div');
153	            div.className = 'autocomplete-item';
154	            // Bold the matching part — escape suggestion text first to prevent XSS
155	            const escaped = escHtml(s);
156	            const esc = q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
157	            div.innerHTML = escaped.replace(new RegExp(`(${esc})`, 'i'), '<strong>$1</strong>');
158	            div.addEventListener('click', function () {
159	                inputEl.value = s;
160	                closeList();
161	                inputEl.dispatchEvent(new Event('autocomplete-select', { bubbles: true }));
162	            });
163	            listEl.appendChild(div);
164	        });
165	        listEl.classList.add('open');
166	    }
167	
168	    function closeList() {
169	        listEl.innerHTML = '';
170	        listEl.classList.remove('open');
171	        activeIndex = -1;
172	    }
173	}
