192	/* ── Image upload validation ─────────────────────────────────── */
193	function initImageUpload(uploadZoneEl, previewsEl, hiddenInputEl) {
194	    if (!uploadZoneEl) return;
195	
196	    const MAX_FILES = 5;
197	    const MAX_SIZE  = 3 * 1024 * 1024; // 3 MB
198	    const ALLOWED   = ['image/jpeg', 'image/png'];
199	
200	    let files = [];
201	
202	    const fileInput = uploadZoneEl.querySelector('input[type="file"]');
203	    if (!fileInput) return;
204	
205	    fileInput.addEventListener('change', handleFiles);
206	
207	    uploadZoneEl.addEventListener('dragover', e => {
208	        e.preventDefault();
209	        uploadZoneEl.classList.add('drag-over');
210	    });
211	    uploadZoneEl.addEventListener('dragleave', () => uploadZoneEl.classList.remove('drag-over'));
212	    uploadZoneEl.addEventListener('drop', e => {
213	        e.preventDefault();
214	        uploadZoneEl.classList.remove('drag-over');
215	        handleFiles({ target: { files: e.dataTransfer.files } });
216	    });
217	
218	    function handleFiles(e) {
219	        const incoming = Array.from(e.target.files || []);
220	        const errors = [];
221	
222	        incoming.forEach(f => {
223	            if (files.length >= MAX_FILES) {
224	                errors.push(`Maximum ${MAX_FILES} images allowed.`);
225	                return;
226	            }
227	            if (!ALLOWED.includes(f.type)) {
228	                errors.push(`${f.name}: only JPG and PNG are accepted.`);
229	                return;
230	            }
231	            if (f.size > MAX_SIZE) {
232	                errors.push(`${f.name}: exceeds 3 MB limit.`);
233	                return;
234	            }
235	            files.push(f);
236	        });
237	
238	        if (errors.length) {
239	            showUploadError(errors.join(' '));
240	        }
241	
242	        renderPreviews();
243	        syncHiddenInput();
244	        fileInput.value = '';
245	    }
246	
247	    function renderPreviews() {
248	        if (!previewsEl) return;
249	        previewsEl.innerHTML = '';
250	        files.forEach((f, i) => {
251	            const wrap = document.createElement('div');
252	            wrap.className = 'upload-preview-item';
253	
254	            const img = document.createElement('img');
255	            img.src = URL.createObjectURL(f);
256	            img.alt = f.name;
257	            wrap.appendChild(img);
258	
259	            const btn = document.createElement('button');
260	            btn.type = 'button';
261	            btn.className = 'upload-preview-remove';
262	            btn.innerHTML = '&times;';
263	            btn.setAttribute('aria-label', 'Remove image');
264	            btn.addEventListener('click', () => {
265	                files.splice(i, 1);
266	                renderPreviews();
267	                syncHiddenInput();
268	            });
269	            wrap.appendChild(btn);
270	            previewsEl.appendChild(wrap);
271	        });
272	    }
273	
274	    function syncHiddenInput() {
275	        if (!hiddenInputEl) return;
276	        const dt = new DataTransfer();
277	        files.forEach(f => dt.items.add(f));
278	        hiddenInputEl.files = dt.files;
279	    }
280	
281	    function showUploadError(msg) {
282	        const errEl = uploadZoneEl.closest('.form-group')?.querySelector('.form-error');
283	        if (errEl) {
284	            errEl.textContent = msg;
285	            errEl.classList.add('visible');
286	            setTimeout(() => errEl.classList.remove('visible'), 4000);
287	        } else {
288	            alert(msg);
289	        }
290	    }
291	
292	    // Expose for external use
293	    uploadZoneEl._getFiles = () => files;
294	}
