296	/* ── Canvas signature pad ────────────────────────────────────── */
297	function initSignaturePad(canvasEl, clearBtnEl, placeholder) {
298	    if (!canvasEl) return null;
299	
300	    const ctx = canvasEl.getContext('2d');
301	    let drawing = false;
302	    let hasStrokes = false;
303	
304	    // Match canvas logical size to its CSS display size
305	    function resize() {
306	        const rect = canvasEl.getBoundingClientRect();
307	        // Preserve existing drawing
308	        const imgData = ctx.getImageData(0, 0, canvasEl.width, canvasEl.height);
309	        canvasEl.width  = rect.width  || 600;
310	        canvasEl.height = rect.height || 240;
311	        ctx.putImageData(imgData, 0, 0);
312	        ctx.strokeStyle = '#111';
313	        ctx.lineWidth   = 2;
314	        ctx.lineCap     = 'round';
315	        ctx.lineJoin    = 'round';
316	    }
317	
318	    resize();
319	
320	    function getPos(e) {
321	        const rect = canvasEl.getBoundingClientRect();
322	        const src  = e.touches ? e.touches[0] : e;
323	        return {
324	            x: (src.clientX - rect.left) * (canvasEl.width  / rect.width),
325	            y: (src.clientY - rect.top)  * (canvasEl.height / rect.height)
326	        };
327	    }
328	
329	    function startDraw(e) {
330	        e.preventDefault();
331	        drawing = true;
332	        const p = getPos(e);
333	        ctx.beginPath();
334	        ctx.moveTo(p.x, p.y);
335	    }
336	
337	    function draw(e) {
338	        if (!drawing) return;
339	        e.preventDefault();
340	        const p = getPos(e);
341	        ctx.lineTo(p.x, p.y);
342	        ctx.stroke();
343	        hasStrokes = true;
344	        if (placeholder) placeholder.classList.add('hidden');
345	    }
346	
347	    function endDraw() { drawing = false; }
348	
349	    // Mouse events
350	    canvasEl.addEventListener('mousedown',  startDraw);
351	    canvasEl.addEventListener('mousemove',  draw);
352	    canvasEl.addEventListener('mouseup',    endDraw);
353	    canvasEl.addEventListener('mouseleave', endDraw);
354	
355	    // Touch events
356	    canvasEl.addEventListener('touchstart', startDraw, { passive: false });
357	    canvasEl.addEventListener('touchmove',  draw,      { passive: false });
358	    canvasEl.addEventListener('touchend',   endDraw);
359	
360	    // Clear button
361	    if (clearBtnEl) {
362	        clearBtnEl.addEventListener('click', function () {
363	            ctx.clearRect(0, 0, canvasEl.width, canvasEl.height);
364	            hasStrokes = false;
365	            if (placeholder) placeholder.classList.remove('hidden');
366	        });
367	    }
368	
369	    window.addEventListener('resize', debounce(resize, 200));
370	
371	    return {
372	        isEmpty:  () => !hasStrokes,
373	        toPNG:    () => canvasEl.toDataURL('image/png'),
374	        toBlob:   (cb) => canvasEl.toBlob(cb, 'image/png'),
375	        clear:    () => clearBtnEl && clearBtnEl.click()
376	    };
377	}
