379	/* ── Appointment slot loader ─────────────────────────────────── */
380	function initSlotLoader(dateInputEl, typeGroupEl, gridEl, hiddenSlotEl) {
381	    if (!dateInputEl || !gridEl) return;
382	
383	    async function loadSlots() {
384	        const date = dateInputEl.value;
385	        if (!date) return;
386	
387	        const type = typeGroupEl
388	            ? (typeGroupEl.querySelector('.toggle-option.active')?.dataset.value || 'OFFLINE')
389	            : 'OFFLINE';
390	
391	        gridEl.innerHTML = '<div class="text-muted mono" style="font-size:.7rem;padding:.5rem;">Loading slots…</div>';
392	
393	        try {
394	            const res = await apiFetch(
395	                `/api/appointments/available?date=${encodeURIComponent(date)}&type=${encodeURIComponent(type)}`
396	            );
397	            if (!res.ok) {
398	                let msg = 'Failed to load slots.';
399	                try {
400	                    const err = await res.json();
401	                    // Surface the server's validation message (e.g. 2-hour minimum, 14-day max)
402	                    msg = err.message || msg;
403	                } catch (_) {}
404	                gridEl.innerHTML = '<div class="text-error mono" style="font-size:.7rem;padding:.5rem;">' +
405	                    msg.replace(/</g, '&lt;') + '</div>';
406	                return;
407	            }
408	            const slots = await res.json();
409	            renderSlots(slots);
410	        } catch (_) {
411	            gridEl.innerHTML = '<div class="text-error mono" style="font-size:.7rem;padding:.5rem;">Network error loading slots. Please try again.</div>';
412	        }
413	    }
414	
415	    function renderSlots(slots) {
416	        gridEl.innerHTML = '';
417	        if (!slots.length) {
418	            gridEl.innerHTML = '<div class="text-muted mono" style="font-size:.7rem;padding:.5rem;">No slots available.</div>';
419	            return;
420	        }
421	        slots.forEach(s => {
422	            const div = document.createElement('div');
423	            div.className = 'slot-item' + (s.available === false ? ' slot-taken' : '');
424	            div.textContent = formatSlotTime(s.startTime) + ' – ' + formatSlotTime(s.endTime);
425	            div.dataset.slotId = s.id;
426	            if (s.available !== false) {
427	                div.addEventListener('click', function () {
428	                    gridEl.querySelectorAll('.slot-item').forEach(el => el.classList.remove('slot-selected'));
429	                    this.classList.add('slot-selected');
430	                    if (hiddenSlotEl) hiddenSlotEl.value = s.id;
431	                });
432	            }
433	            gridEl.appendChild(div);
434	        });
435	    }
436	
437	    function formatSlotTime(t) {
438	        if (!t) return '';
439	        // t may be "HH:mm:ss" or ISO
440	        const parts = t.split(':');
441	        if (parts.length >= 2) {
442	            let h = parseInt(parts[0], 10);
443	            const m = parts[1].padStart(2, '0');
444	            const ampm = h >= 12 ? 'PM' : 'AM';
445	            h = h % 12 || 12;
446	            return `${h}:${m} ${ampm}`;
447	        }
448	        return t;
449	    }
450	
451	    dateInputEl.addEventListener('change', loadSlots);
452	
453	    if (typeGroupEl) {
454	        typeGroupEl.querySelectorAll('.toggle-option').forEach(btn => {
455	            btn.addEventListener('click', function () {
456	                typeGroupEl.querySelectorAll('.toggle-option').forEach(b => b.classList.remove('active'));
457	                this.classList.add('active');
458	                loadSlots();
459	            });
460	        });
461	    }
462	}
