81	(function () {
82	    const form        = document.getElementById('changePasswordForm');
83	    const alertBox    = document.getElementById('alertBox');
84	    const successBox  = document.getElementById('successBox');
85	    const submitBtn   = document.getElementById('submitBtn');
86	    const btnLabel    = document.getElementById('btnLabel');
87	    const btnSpinner  = document.getElementById('btnSpinner');
88	
89	    function setLoading(on) {
90	        submitBtn.disabled = on;
91	        btnLabel.classList.toggle('hidden', on);
92	        btnSpinner.classList.toggle('hidden', !on);
93	    }
94	
95	    form.addEventListener('submit', async function (e) {
96	        e.preventDefault();
97	
98	        hideAlert(alertBox);
99	        hideAlert(successBox);
100	
101	        const oldPassword     = document.getElementById('oldPassword').value;
102	        const newPassword     = document.getElementById('newPassword').value;
103	        const confirmPassword = document.getElementById('confirmPassword').value;
104	
105	        // Client-side validation
106	        if (!oldPassword) {
107	            showAlert(alertBox, 'Please enter your current password.', 'error');
108	            return;
109	        }
110	        if (newPassword.length < 12) {
111	            showAlert(alertBox, 'New password must be at least 12 characters.', 'error');
112	            return;
113	        }
114	        if (newPassword !== confirmPassword) {
115	            showAlert(alertBox, 'New passwords do not match.', 'error');
116	            return;
117	        }
118	
119	        setLoading(true);
120	
121	        try {
122	            const res = await apiFetch('/api/auth/change-password', {
123	                method: 'POST',
124	                body: JSON.stringify({ oldPassword, newPassword, confirmPassword })
125	            });
126	
127	            if (res.ok) {
128	                showAlert(successBox, 'Password updated successfully. Redirecting…', 'success');
129	                setTimeout(() => { window.location.href = '/user/dashboard'; }, 2000);
130	                return;
131	            }
132	
133	            let msg = 'Failed to update password.';
134	            try {
135	                const err = await res.json();
136	                msg = err.message || err.error || msg;
137	            } catch (_) {}
138	            showAlert(alertBox, msg, 'error');
139	
140	        } catch (_) {
141	            showAlert(alertBox, 'Network error. Please try again.', 'error');
142	        } finally {
143	            setLoading(false);
144	        }
145	    });
146	})();
147	</script>
