19	import org.springframework.web.bind.annotation.*;
20	
21	@RestController
22	@RequestMapping("/api/auth")
23	public class AuthApiController {
24	
25	    private static final String REFRESH_COOKIE_NAME = "refreshToken";
26	    private static final int REFRESH_COOKIE_MAX_AGE = 7 * 24 * 60 * 60; // 7 days in seconds
27	
28	    private final AuthService authService;
29	    private final UserRepository userRepository;
30	    private final ReclaimProperties reclaimProperties;
31	
32	    public AuthApiController(AuthService authService,
33	                             UserRepository userRepository,
34	                             ReclaimProperties reclaimProperties) {
35	        this.authService = authService;
36	        this.userRepository = userRepository;
37	        this.reclaimProperties = reclaimProperties;
38	    }
39	
40	    @PostMapping("/login")
41	    public ResponseEntity<AuthResponse> login(@Valid @RequestBody LoginRequest request,
42	                                              HttpServletRequest httpRequest,
43	                                              HttpServletResponse httpResponse) {
44	        String ipAddress = resolveIpAddress(httpRequest);
45	        AuthResponse authResponse = authService.login(
46	            request.getUsername(), request.getPassword(), ipAddress);
47	
48	        setRefreshCookie(httpResponse, authResponse.getRefreshToken());
49	        setAccessTokenCookie(httpResponse, authResponse.getAccessToken());
50	
51	        AuthResponse responseBody = new AuthResponse(
52	            authResponse.getAccessToken(),
53	            null,
54	            authResponse.isForcePasswordReset()
55	        );
56	        return ResponseEntity.ok(responseBody);
57	    }
58	
59	    @PostMapping("/refresh")
60	    public ResponseEntity<AuthResponse> refresh(HttpServletRequest httpRequest,
61	                                                HttpServletResponse httpResponse) {
62	        validateOrigin(httpRequest);
63	
64	        String refreshTokenStr = extractRefreshCookie(httpRequest);
65	        if (refreshTokenStr == null) {
66	            return ResponseEntity.badRequest().build();
67	        }
68	
69	        AuthResponse authResponse = authService.refresh(refreshTokenStr);
70	        setRefreshCookie(httpResponse, authResponse.getRefreshToken());
71	        setAccessTokenCookie(httpResponse, authResponse.getAccessToken());
72	
73	        AuthResponse responseBody = new AuthResponse(
74	            authResponse.getAccessToken(),
75	            null,
76	            authResponse.isForcePasswordReset()
77	        );
78	        return ResponseEntity.ok(responseBody);
79	    }
80	
81	    @PostMapping("/logout")
82	    public ResponseEntity<Void> logout(HttpServletRequest httpRequest,
83	                                       HttpServletResponse httpResponse) {
84	        validateOrigin(httpRequest);
85	
86	        String refreshTokenStr = extractRefreshCookie(httpRequest);
87	        if (refreshTokenStr != null) {
88	            authService.logout(refreshTokenStr);
89	        }
90	        clearRefreshCookie(httpResponse);
91	        clearAccessTokenCookie(httpResponse);
92	        return ResponseEntity.ok().build();
93	    }
94	
95	    @PostMapping("/change-password")
96	    public ResponseEntity<Void> changePassword(@Valid @RequestBody ChangePasswordRequest request,
97	                                               Authentication authentication) {
98	        UserDetails userDetails = (UserDetails) authentication.getPrincipal();
99	        User user = userRepository.findByUsername(userDetails.getUsername())
100	            .orElseThrow(() -> new EntityNotFoundException(
101	                "User not found: " + userDetails.getUsername()));
102	
103	        authService.changePassword(user.getId(), request.getOldPassword(), request.getNewPassword());
104	        return ResponseEntity.ok().build();
105	    }
106	
107	    private void setRefreshCookie(HttpServletResponse response, String refreshToken) {
108	        ResponseCookie cookie = ResponseCookie.from(REFRESH_COOKIE_NAME, refreshToken)
109	            .httpOnly(true)
110	            .secure(reclaimProperties.getSecurity().isCookieSecure())
111	            .path("/api/auth")
112	            .maxAge(REFRESH_COOKIE_MAX_AGE)
113	            .sameSite("Strict")
114	            .build();
115	        response.addHeader("Set-Cookie", cookie.toString());
116	    }
117	
118	    private void clearRefreshCookie(HttpServletResponse response) {
119	        ResponseCookie cookie = ResponseCookie.from(REFRESH_COOKIE_NAME, "")
120	            .httpOnly(true)
121	            .secure(reclaimProperties.getSecurity().isCookieSecure())
122	            .path("/api/auth")
123	            .maxAge(0)
124	            .sameSite("Strict")
125	            .build();
126	        response.addHeader("Set-Cookie", cookie.toString());
127	    }
128	
129	    private void setAccessTokenCookie(HttpServletResponse response, String accessToken) {
130	        ResponseCookie cookie = ResponseCookie.from("accessToken", accessToken)
131	            .httpOnly(true)
132	            .secure(reclaimProperties.getSecurity().isCookieSecure())
133	            .path("/")
134	            .maxAge(reclaimProperties.getSecurity().getAccessTokenMinutes() * 60)
135	            .sameSite("Strict")
136	            .build();
137	        response.addHeader("Set-Cookie", cookie.toString());
138	    }
139	
140	    private void clearAccessTokenCookie(HttpServletResponse response) {
141	        ResponseCookie cookie = ResponseCookie.from("accessToken", "")
142	            .httpOnly(true)
143	            .secure(reclaimProperties.getSecurity().isCookieSecure())
144	            .path("/")
145	            .maxAge(0)
146	            .sameSite("Strict")
147	            .build();
148	        response.addHeader("Set-Cookie", cookie.toString());
149	    }
150	
151	    private String extractRefreshCookie(HttpServletRequest request) {
152	        if (request.getCookies() == null) {
153	            return null;
154	        }
155	        for (Cookie cookie : request.getCookies()) {
156	            if (REFRESH_COOKIE_NAME.equals(cookie.getName())) {
157	                return cookie.getValue();
158	            }
159	        }
160	        return null;
161	    }
162	
163	    private String resolveIpAddress(HttpServletRequest request) {
164	        String xForwardedFor = request.getHeader("X-Forwarded-For");
165	        if (xForwardedFor != null && !xForwardedFor.isBlank()) {
166	            return xForwardedFor.split(",")[0].trim();
167	        }
168	        return request.getRemoteAddr();
169	    }
170	
171	    /**
172	     * Validates the Origin header on cookie-bearing endpoints (refresh, logout) as a
173	     * defence-in-depth CSRF mitigation alongside the SameSite=Strict cookie attribute.
174	     *
175	     * If no Origin header is present the request is allowed — same-origin requests from the
176	     * same page do not always include Origin. Only explicit cross-origin requests that set a
177	     * different Origin are rejected.
178	     */
179	    private void validateOrigin(HttpServletRequest request) {
180	        String origin = request.getHeader("Origin");
181	        if (origin != null && !origin.isEmpty()) {
182	            String expectedOrigin = request.getScheme() + "://" + request.getServerName();
183	            int port = request.getServerPort();
184	            if (port != 80 && port != 443) {
185	                expectedOrigin += ":" + port;
186	            }
187	            if (!origin.equals(expectedOrigin)) {
188	                throw new com.reclaim.portal.common.exception.BusinessRuleException(
189	                    "Cross-origin request rejected");
190	            }
191	        }
192	    }
193	}
