{"file_path": "/Users/aimanmengesha/Desktop/eagle point/Slopering/w2t42/repo/src/main/java/com/reclaim/portal/orders/config/ImmutableLogTriggerInitializer.java", "content": "package com.reclaim.portal.orders.config;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.boot.ApplicationArguments;
import org.springframework.boot.ApplicationRunner;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Component;

/**
 * Creates H2-compatible immutability triggers on order_operation_logs at startup.
 *
 * <p>On MySQL the triggers are created by Flyway migration V9 using {@code SIGNAL SQLSTATE}.
 * H2 does not support that syntax, so this runner creates equivalent triggers using H2's
 * {@code CALL} syntax with {@link ImmutableLogTrigger}. On MySQL this runner is a no-op
 * because the triggers already exist.
 *
 * <p>Follows the same pattern as {@link com.reclaim.portal.catalog.config.FullTextIndexInitializer}.
 */
@Component
public class ImmutableLogTriggerInitializer implements ApplicationRunner {

    private static final Logger log = LoggerFactory.getLogger(ImmutableLogTriggerInitializer.class);

    private final JdbcTemplate jdbcTemplate;

    public ImmutableLogTriggerInitializer(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }

    @Override
    public void run(ApplicationArguments args) {
        createTriggerIfMissing(
            "prevent_oplog_update", "UPDATE",
            "CREATE TRIGGER prevent_oplog_update BEFORE UPDATE ON order_operation_logs " +
            "FOR EACH ROW CALL \"com.reclaim.portal.orders.config.ImmutableLogTrigger\""
        );
        createTriggerIfMissing(
            "prevent_oplog_delete", "DELETE",
            "CREATE TRIGGER prevent_oplog_delete BEFORE DELETE ON order_operation_logs " +
            "FOR EACH ROW CALL \"com.reclaim.portal.orders.config.ImmutableLogTrigger\""
        );
    }

    private void createTriggerIfMissing(String triggerName, String event, String createSql) {
        try {
            // Check if trigger already exists (works on both MySQL and H2)
            var rows = jdbcTemplate.queryForList(
                "SELECT TRIGGER_NAME FROM INFORMATION_SCHEMA.TRIGGERS " +
                "WHERE EVENT_OBJECT_TABLE = 'order_operation_logs' " +
                "AND EVENT_MANIPULATION = ? AND TRIGGER_NAME = ?",
                event, triggerName.toUpperCase()
            );
            if (!rows.isEmpty()) {
                log.debug("Trigger {} already exists on order_operation_logs.", triggerName);
                return;
            }
            jdbcTemplate.execute(createSql);
            log.info("Created immutability trigger {} on order_operation_logs.", triggerName);
        } catch (Exception e) {
            // Expected on MySQL where V9 migration already created the triggers,
            // or if INFORMATION_SCHEMA query syntax differs
            log.info("Immutability trigger {} setup skipped: {}", triggerName, e.getMessage());
        }
    }
}
"}

